{
  "name": "Shree Ganesh Flex Billing System",
  "description": "A comprehensive billing and management software for advertising businesses, featuring service selection, square footage calculation, automated WhatsApp reminders, and CSV data export.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface Service {
  id: string;
  name: string;
  defaultRate: number; // rate per sqft or per unit
  category: 'sqft' | 'unit';
}

export interface BillItem {
  id: string;
  serviceId: string;
  serviceName: string;
  width: number;
  height: number;
  sqft: number;
  rate: number;
  quantity: number;
  amount: number;
}

export interface Bill {
  id: string;
  customerName: string;
  customerPhone: string;
  date: string;
  time: string;
  items: BillItem[];
  totalAmount: number;
  status: 'Pending' | 'Paid';
  notes: string;
}

export type AppView = 'Billing' | 'History' | 'Analytics';

import { Service } from './types';

export const DEFAULT_SERVICES: Service[] = [
  { id: '1', name: 'Flex Banner', defaultRate: 12, category: 'sqft' },
  { id: '2', name: 'Vinyl Printing', defaultRate: 25, category: 'sqft' },
  { id: '3', name: 'Star Flex', defaultRate: 20, category: 'sqft' },
  { id: '4', name: 'Hoarding Board', defaultRate: 50, category: 'sqft' },
  { id: '5', name: 'Visiting Cards (1000)', defaultRate: 800, category: 'unit' },
  { id: '6', name: 'Patrika Printing', defaultRate: 5, category: 'unit' },
  { id: '7', name: 'One-Way Vision', defaultRate: 45, category: 'sqft' },
  { id: '8', name: 'ACP Board', defaultRate: 180, category: 'sqft' },
  { id: '9', name: 'Sunboard Printing', defaultRate: 60, category: 'sqft' },
];

export const APP_TITLE = "Shree Ganesh Flex & Advertising";

import { GoogleGenAI } from "@google/genai";
import { Bill } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateReminderMessage = async (bill: Bill): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a polite and professional WhatsApp reminder message for a customer named ${bill.customerName} who has a pending bill of ₹${bill.totalAmount} at "Shree Ganesh Flex & Advertising". The bill date was ${bill.date}. Keep it concise and include a call to action to settle the payment.`,
    });
    return response.text || `Hello ${bill.customerName}, this is a reminder regarding your pending payment of ₹${bill.totalAmount} at Shree Ganesh Flex. Please settle it at your earliest convenience. Thank you!`;
  } catch (error) {
    console.error("Gemini Error:", error);
    return `Hello ${bill.customerName}, reminder for your pending bill of ₹${bill.totalAmount}. - Shree Ganesh Flex`;
  }
};

export const getBusinessInsights = async (bills: Bill[]): Promise<string> => {
  if (bills.length === 0) return "No data yet to analyze.";

  const totalSales = bills.reduce((sum, b) => sum + b.totalAmount, 0);
  const pendingAmount = bills.filter(b => b.status === 'Pending').reduce((sum, b) => sum + b.totalAmount, 0);

  const summary = `
    Total Sales: ₹${totalSales}
    Pending Amount: ₹${pendingAmount}
    Total Orders: ${bills.length}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Based on this sales summary: ${summary}, provide 2-3 short, actionable business tips to improve revenue or payment collection for Shree Ganesh Flex & Advertising.`,
    });
    return response.text || "Keep track of your pending payments regularly.";
  } catch (error) {
    return "Keep growing your business!";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Bill, Service, AppView } from './types';
import { DEFAULT_SERVICES, APP_TITLE } from './constants';
import BillingView from './components/BillingView';
import HistoryView from './components/HistoryView';
import InsightsView from './components/InsightsView';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('Billing');
  const [bills, setBills] = useState<Bill[]>([]);

  // Load data from local storage on mount
  useEffect(() => {
    const savedBills = localStorage.getItem('sganesh_bills');
    if (savedBills) {
      setBills(JSON.parse(savedBills));
    }
  }, []);

  // Save data to local storage when bills change
  useEffect(() => {
    localStorage.setItem('sganesh_bills', JSON.stringify(bills));
  }, [bills]);

  const addBill = useCallback((newBill: Bill) => {
    setBills(prev => [newBill, ...prev]);
  }, []);

  const updateBillStatus = useCallback((id: string, status: 'Pending' | 'Paid') => {
    setBills(prev => prev.map(bill => 
      bill.id === id ? { ...bill, status } : bill
    ));
  }, []);

  const deleteBill = useCallback((id: string) => {
    if (window.confirm("Are you sure you want to delete this bill?")) {
      setBills(prev => prev.filter(bill => bill.id !== id));
    }
  }, []);

  const exportToCSV = () => {
    if (bills.length === 0) return alert("No data to export");

    const headers = ["ID", "Customer", "Phone", "Date", "Time", "Total", "Status", "Items"];
    const rows = bills.map(b => [
      b.id,
      b.customerName,
      b.customerPhone,
      b.date,
      b.time,
      b.totalAmount,
      b.status,
      b.items.map(i => `${i.serviceName}(${i.quantity})`).join('; ')
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `billing_backup_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col">
        <div className="p-6 border-b border-slate-800">
          <h1 className="text-xl font-bold text-orange-400 leading-tight">
            {APP_TITLE}
          </h1>
          <p className="text-xs text-slate-400 mt-1 uppercase tracking-wider font-semibold">Management Console</p>
        </div>

        <div className="flex-1 py-4">
          <button 
            onClick={() => setView('Billing')}
            className={`w-full text-left px-6 py-3 flex items-center space-x-3 transition-colors ${view === 'Billing' ? 'bg-orange-500 text-white' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-file-invoice-dollar w-6"></i>
            <span>Create Bill</span>
          </button>
          <button 
            onClick={() => setView('History')}
            className={`w-full text-left px-6 py-3 flex items-center space-x-3 transition-colors ${view === 'History' ? 'bg-orange-500 text-white' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-history w-6"></i>
            <span>Bill History</span>
          </button>
          <button 
            onClick={() => setView('Analytics')}
            className={`w-full text-left px-6 py-3 flex items-center space-x-3 transition-colors ${view === 'Analytics' ? 'bg-orange-500 text-white' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-chart-line w-6"></i>
            <span>Insights</span>
          </button>
        </div>

        <div className="p-4 border-t border-slate-800 space-y-2">
          <button 
            onClick={exportToCSV}
            className="w-full bg-slate-800 hover:bg-slate-700 text-white py-2 px-4 rounded-md text-sm flex items-center justify-center space-x-2 transition-colors"
          >
            <i className="fas fa-download"></i>
            <span>Backup CSV</span>
          </button>
          <div className="text-[10px] text-center text-slate-500">
            Powered by Gemini AI
          </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 bg-gray-50 overflow-y-auto">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {view === 'Billing' && <BillingView onSave={addBill} />}
          {view === 'History' && (
            <HistoryView 
              bills={bills} 
              onUpdateStatus={updateBillStatus} 
              onDelete={deleteBill} 
            />
          )}
          {view === 'Analytics' && <InsightsView bills={bills} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Bill, BillItem, Service } from '../types';
import { DEFAULT_SERVICES } from '../constants';

interface BillingViewProps {
  onSave: (bill: Bill) => void;
}

const BillingView: React.FC<BillingViewProps> = ({ onSave }) => {
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [selectedItems, setSelectedItems] = useState<BillItem[]>([]);
  const [notes, setNotes] = useState('');

  const addServiceToBill = (service: Service) => {
    const newItem: BillItem = {
      id: Math.random().toString(36).substr(2, 9),
      serviceId: service.id,
      serviceName: service.name,
      width: service.category === 'sqft' ? 1 : 0,
      height: service.category === 'sqft' ? 1 : 0,
      sqft: service.category === 'sqft' ? 1 : 0,
      rate: service.defaultRate,
      quantity: 1,
      amount: service.defaultRate,
    };
    setSelectedItems(prev => [...prev, newItem]);
  };

  const updateItem = (id: string, updates: Partial<BillItem>) => {
    setSelectedItems(prev => prev.map(item => {
      if (item.id !== id) return item;

      const updated = { ...item, ...updates };

      // Recalculate SQFT if width/height changed
      if (updates.width !== undefined || updates.height !== undefined) {
        updated.sqft = updated.width * updated.height;
      }

      // Recalculate Amount
      const service = DEFAULT_SERVICES.find(s => s.id === updated.serviceId);
      if (service?.category === 'sqft') {
        updated.amount = updated.sqft * updated.rate * updated.quantity;
      } else {
        updated.amount = updated.rate * updated.quantity;
      }

      return updated;
    }));
  };

  const removeItem = (id: string) => {
    setSelectedItems(prev => prev.filter(i => i.id !== id));
  };

  const totalAmount = selectedItems.reduce((sum, item) => sum + item.amount, 0);

  const handleSave = () => {
    if (!customerName || selectedItems.length === 0) {
      alert("Please enter customer name and add at least one item.");
      return;
    }

    const newBill: Bill = {
      id: `INV-${Date.now()}`,
      customerName,
      customerPhone,
      date: new Date().toLocaleDateString(),
      time: new Date().toLocaleTimeString(),
      items: selectedItems,
      totalAmount,
      status: 'Pending',
      notes
    };

    onSave(newBill);
    // Reset form
    setCustomerName('');
    setCustomerPhone('');
    setSelectedItems([]);
    setNotes('');
    alert("Bill saved successfully!");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
      {/* Services Sidebar */}
      <div className="lg:col-span-3 space-y-4">
        <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
          <h3 className="font-bold text-gray-800 mb-4 flex items-center">
            <i className="fas fa-concierge-bell mr-2 text-orange-500"></i>
            Select Services
          </h3>
          <div className="grid grid-cols-1 gap-2">
            {DEFAULT_SERVICES.map(service => (
              <button
                key={service.id}
                onClick={() => addServiceToBill(service)}
                className="text-left p-3 rounded-lg border border-gray-100 hover:border-orange-300 hover:bg-orange-50 transition-all flex justify-between items-center group"
              >
                <span className="text-sm font-medium text-gray-700">{service.name}</span>
                <i className="fas fa-plus text-gray-300 group-hover:text-orange-500 text-xs"></i>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Bill Editor */}
      <div className="lg:col-span-9 space-y-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
            <h2 className="text-xl font-bold text-gray-800">New Bill</h2>
            <div className="flex gap-4">
              <input
                type="text"
                placeholder="Customer Name"
                className="border-gray-200 border rounded-lg px-4 py-2 focus:ring-2 focus:ring-orange-500 focus:outline-none flex-1"
                value={customerName}
                onChange={e => setCustomerName(e.target.value)}
              />
              <input
                type="text"
                placeholder="Phone (WhatsApp)"
                className="border-gray-200 border rounded-lg px-4 py-2 focus:ring-2 focus:ring-orange-500 focus:outline-none flex-1"
                value={customerPhone}
                onChange={e => setCustomerPhone(e.target.value)}
              />
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="border-b border-gray-100 bg-gray-50">
                <tr>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase">Service</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase">Size (W x H)</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase text-center">SQFT</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase text-center">Rate</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase text-center">Qty</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase text-right">Amount</th>
                  <th className="py-3 px-4"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {selectedItems.map(item => {
                  const isSqft = DEFAULT_SERVICES.find(s => s.id === item.serviceId)?.category === 'sqft';
                  return (
                    <tr key={item.id} className="hover:bg-gray-50 transition-colors">
                      <td className="py-4 px-4 font-medium text-gray-800">{item.serviceName}</td>
                      <td className="py-4 px-4">
                        {isSqft && (
                          <div className="flex items-center space-x-2">
                            <input 
                              type="number" 
                              className="w-16 border border-gray-200 rounded px-2 py-1 text-sm"
                              value={item.width}
                              onChange={e => updateItem(item.id, { width: parseFloat(e.target.value) || 0 })}
                            />
                            <span className="text-gray-400">×</span>
                            <input 
                              type="number" 
                              className="w-16 border border-gray-200 rounded px-2 py-1 text-sm"
                              value={item.height}
                              onChange={e => updateItem(item.id, { height: parseFloat(e.target.value) || 0 })}
                            />
                          </div>
                        )}
                      </td>
                      <td className="py-4 px-4 text-center text-sm text-gray-600">
                        {isSqft ? item.sqft.toFixed(2) : '-'}
                      </td>
                      <td className="py-4 px-4 text-center">
                        <input 
                          type="number" 
                          className="w-20 border border-gray-200 rounded px-2 py-1 text-sm text-center"
                          value={item.rate}
                          onChange={e => updateItem(item.id, { rate: parseFloat(e.target.value) || 0 })}
                        />
                      </td>
                      <td className="py-4 px-4 text-center">
                        <input 
                          type="number" 
                          className="w-16 border border-gray-200 rounded px-2 py-1 text-sm text-center font-bold"
                          value={item.quantity}
                          onChange={e => updateItem(item.id, { quantity: parseInt(e.target.value) || 0 })}
                        />
                      </td>
                      <td className="py-4 px-4 text-right font-bold text-gray-800">
                        ₹{item.amount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                      </td>
                      <td className="py-4 px-4 text-right">
                        <button 
                          onClick={() => removeItem(item.id)}
                          className="text-red-400 hover:text-red-600 transition-colors"
                        >
                          <i className="fas fa-trash"></i>
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          {selectedItems.length === 0 && (
            <div className="py-12 text-center text-gray-400">
              <i className="fas fa-shopping-cart text-3xl mb-3 block"></i>
              No services added to bill yet.
            </div>
          )}

          <div className="mt-8 pt-6 border-t border-gray-100 flex flex-col md:flex-row justify-between items-start gap-6">
            <div className="w-full md:w-1/2">
              <label className="block text-sm font-semibold text-gray-600 mb-2">Notes / Additional Info</label>
              <textarea
                className="w-full border border-gray-200 rounded-lg p-3 text-sm focus:ring-2 focus:ring-orange-500 focus:outline-none"
                rows={3}
                placeholder="Enter any special instructions..."
                value={notes}
                onChange={e => setNotes(e.target.value)}
              />
            </div>
            <div className="w-full md:w-1/3 bg-gray-50 p-6 rounded-xl border border-gray-200">
              <div className="flex justify-between items-center mb-2">
                <span className="text-gray-500">Subtotal:</span>
                <span className="font-semibold text-gray-700">₹{totalAmount.toLocaleString('en-IN')}</span>
              </div>
              <div className="flex justify-between items-center mb-6 pt-2 border-t border-gray-200">
                <span className="text-xl font-bold text-gray-800">Total:</span>
                <span className="text-2xl font-black text-orange-600">₹{totalAmount.toLocaleString('en-IN')}</span>
              </div>
              <button 
                onClick={handleSave}
                disabled={selectedItems.length === 0}
                className={`w-full py-4 rounded-xl font-bold text-white shadow-lg shadow-orange-200 transition-all ${
                  selectedItems.length > 0 ? 'bg-orange-500 hover:bg-orange-600 active:transform active:scale-95' : 'bg-gray-300 cursor-not-allowed'
                }`}
              >
                <i className="fas fa-check-circle mr-2"></i>
                GENERATE & SAVE BILL
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BillingView;

import React, { useState } from 'react';
import { Bill } from '../types';
import { generateReminderMessage } from '../services/geminiService';

interface HistoryViewProps {
  bills: Bill[];
  onUpdateStatus: (id: string, status: 'Pending' | 'Paid') => void;
  onDelete: (id: string) => void;
}

const HistoryView: React.FC<HistoryViewProps> = ({ bills, onUpdateStatus, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sendingId, setSendingId] = useState<string | null>(null);

  const filteredBills = bills.filter(bill => 
    bill.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    bill.customerPhone.includes(searchTerm) ||
    bill.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleWhatsApp = async (bill: Bill) => {
    if (!bill.customerPhone) {
      alert("No phone number found for this customer.");
      return;
    }

    setSendingId(bill.id);
    const message = await generateReminderMessage(bill);
    setSendingId(null);

    const encodedMsg = encodeURIComponent(message);
    const phone = bill.customerPhone.replace(/\D/g, '');
    window.open(`https://wa.me/${phone.startsWith('91') ? phone : '91' + phone}?text=${encodedMsg}`, '_blank');
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-bold text-gray-800">Billing Records</h2>
        <div className="relative w-full md:w-96">
          <i className="fas fa-search absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
          <input
            type="text"
            placeholder="Search by name, phone or bill ID..."
            className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-orange-500 focus:outline-none"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50 border-b border-gray-100">
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">Bill Info</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">Customer</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase text-right">Amount</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase text-center">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredBills.map(bill => (
                <tr key={bill.id} className="hover:bg-gray-50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="text-sm font-bold text-gray-900">{bill.id}</div>
                    <div className="text-xs text-gray-500">{bill.date} @ {bill.time}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm font-semibold text-gray-800">{bill.customerName}</div>
                    <div className="text-xs text-gray-500 flex items-center mt-1">
                      <i className="fab fa-whatsapp text-green-500 mr-1"></i>
                      {bill.customerPhone || 'N/A'}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="text-sm font-black text-gray-900">₹{bill.totalAmount.toLocaleString('en-IN')}</div>
                    <div className="text-xs text-gray-400">{bill.items.length} items</div>
                  </td>
                  <td className="px-6 py-4 text-center">
                    <button 
                      onClick={() => onUpdateStatus(bill.id, bill.status === 'Paid' ? 'Pending' : 'Paid')}
                      className={`px-3 py-1.5 rounded-full text-xs font-bold inline-flex items-center space-x-1 border transition-all ${
                        bill.status === 'Paid' 
                          ? 'bg-green-50 text-green-700 border-green-200 hover:bg-green-100' 
                          : 'bg-red-50 text-red-700 border-red-200 hover:bg-red-100'
                      }`}
                    >
                      <span className={`w-2 h-2 rounded-full ${bill.status === 'Paid' ? 'bg-green-500' : 'bg-red-500'}`}></span>
                      <span>{bill.status}</span>
                    </button>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end space-x-2">
                      {bill.status === 'Pending' && (
                        <button
                          onClick={() => handleWhatsApp(bill)}
                          disabled={sendingId === bill.id}
                          className="p-2 text-green-600 bg-green-50 hover:bg-green-100 rounded-lg transition-colors flex items-center gap-1 text-sm disabled:opacity-50"
                          title="Send WhatsApp Reminder"
                        >
                          <i className={`fab fa-whatsapp ${sendingId === bill.id ? 'animate-spin' : ''}`}></i>
                          <span className="hidden lg:inline">Remind</span>
                        </button>
                      )}
                      <button
                        onClick={() => onDelete(bill.id)}
                        className="p-2 text-red-600 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
                        title="Delete Record"
                      >
                        <i className="fas fa-trash-alt"></i>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filteredBills.length === 0 && (
          <div className="p-20 text-center text-gray-400 bg-white">
            <i className="fas fa-folder-open text-4xl mb-4 block opacity-20"></i>
            No matching records found.
          </div>
        )}
      </div>
    </div>
  );
};

