interface InsightsViewProps {
  bills: Bill[];
}

const InsightsView: React.FC<InsightsViewProps> = ({ bills }) => {
  const [insight, setInsight] = useState<string>('Generating AI insights...');
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchInsights = async () => {
      setIsLoading(true);
      const res = await getBusinessInsights(bills);
      setInsight(res);
      setIsLoading(false);
    };
    fetchInsights();
  }, [bills]);

  const totalRevenue = bills.reduce((acc, bill) => acc + bill.totalAmount, 0);
  const totalPaid = bills.filter(b => b.status === 'Paid').reduce((acc, bill) => acc + bill.totalAmount, 0);
  const totalPending = bills.filter(b => b.status === 'Pending').reduce((acc, bill) => acc + bill.totalAmount, 0);

  // Group by date for simple chart
  const last7Days = Array.from({ length: 7 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - i);
    return d.toLocaleDateString();
