          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-green-50 text-green-600 rounded-xl">
              <i className="fas fa-check-double text-2xl"></i>
            </div>
            <div>
              <p className="text-sm text-gray-500 font-medium">Collection</p>
              <h4 className="text-2xl font-black text-green-600">₹{totalPaid.toLocaleString('en-IN')}</h4>
