import React, { useState, useEffect, useCallback } from 'react';
import { Bill, Service, AppView } from './types';
import { DEFAULT_SERVICES, APP_TITLE } from './constants';
import BillingView from './components/BillingView';
import HistoryView from './components/HistoryView';
import InsightsView from './components/InsightsView';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('Billing');
  const [bills, setBills] = useState<Bill[]>([]);
  const [services, setServices] = useState<Service[]>(DEFAULT_SERVICES);

  // Load data from local storage on mount
  useEffect(() => {
    const savedBills = localStorage.getItem('sganesh_bills');
    if (savedBills) {
      try {
        setBills(JSON.parse(savedBills));
      } catch (e) {
        console.error("Failed to parse bills", e);
      }
    }

    const savedServices = localStorage.getItem('sganesh_services');
    if (savedServices) {
      try {
        setServices(JSON.parse(savedServices));
      } catch (e) {
        console.error("Failed to parse services", e);
        setServices(DEFAULT_SERVICES);
      }
    }
  }, []);

  // Save bills to local storage when they change
  useEffect(() => {
    localStorage.setItem('sganesh_bills', JSON.stringify(bills));
  }, [bills]);

  // Save services to local storage when they change
  useEffect(() => {
    localStorage.setItem('sganesh_services', JSON.stringify(services));
  }, [services]);

  const addBill = useCallback((newBill: Bill) => {
    setBills(prev => [newBill, ...prev]);
  }, []);

  const updateBillStatus = useCallback((id: string, status: 'Pending' | 'Paid') => {
    setBills(prev => prev.map(bill => 
      bill.id === id ? { ...bill, status } : bill
    ));
  }, []);

  const deleteBill = useCallback((id: string) => {
    if (window.confirm("Are you sure you want to delete this bill?")) {
      setBills(prev => prev.filter(bill => bill.id !== id));
    }
  }, []);

  const addService = (service: Service) => {
    setServices(prev => [...prev, service]);
  };

  const deleteService = (id: string) => {
    if (window.confirm("Delete this service? It will no longer appear in the selection list.")) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const exportToCSV = () => {
    if (bills.length === 0) return alert("No data to export");

    const headers = ["ID", "Customer", "Phone", "Date", "Time", "Total", "Status", "Items"];
    const rows = bills.map(b => [
      b.id,
      b.customerName,
      b.customerPhone,
      b.date,
      b.time,
      b.totalAmount,
      b.status,
      b.items.map(i => `${i.serviceName}(${i.quantity})`).join('; ')
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `billing_backup_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col">
        <div className="p-6 border-b border-slate-800">
          <h1 className="text-xl font-bold text-orange-400 leading-tight">
            {APP_TITLE}
          </h1>
          <p className="text-xs text-slate-400 mt-1 uppercase tracking-wider font-semibold">Management Console</p>
        </div>

        <div className="flex-1 py-4">
          <button 
            onClick={() => setView('Billing')}
            className={`w-full text-left px-6 py-3 flex items-center space-x-3 transition-colors ${view === 'Billing' ? 'bg-orange-500 text-white' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-file-invoice-dollar w-6"></i>
            <span>Create Bill</span>
          </button>
          <button 
            onClick={() => setView('History')}
            className={`w-full text-left px-6 py-3 flex items-center space-x-3 transition-colors ${view === 'History' ? 'bg-orange-500 text-white' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-history w-6"></i>
            <span>Bill History</span>
          </button>
          <button 
            onClick={() => setView('Analytics')}
            className={`w-full text-left px-6 py-3 flex items-center space-x-3 transition-colors ${view === 'Analytics' ? 'bg-orange-500 text-white' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-chart-line w-6"></i>
            <span>Reports</span>
          </button>
        </div>

        <div className="p-4 border-t border-slate-800 space-y-2">
          <button 
            onClick={exportToCSV}
            className="w-full bg-slate-800 hover:bg-slate-700 text-white py-2 px-4 rounded-md text-sm flex items-center justify-center space-x-2 transition-colors"
          >
            <i className="fas fa-download"></i>
            <span>Backup CSV</span>
          </button>
          <div className="text-[10px] text-center text-slate-500">
            Shree Ganesh Flex System v2.0
          </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {view === 'Billing' && (
            <BillingView 
              services={services} 
              onSave={addBill} 
              onAddService={addService}
              onDeleteService={deleteService}
            />
          )}
          {view === 'History' && (
            <HistoryView 
              bills={bills} 
              onUpdateStatus={updateBillStatus} 
              onDelete={deleteBill} 
            />
          )}
          {view === 'Analytics' && <InsightsView bills={bills} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Bill, BillItem, Service } from '../types';

interface BillingViewProps {
  services: Service[];
  onSave: (bill: Bill) => void;
  onAddService: (service: Service) => void;
  onDeleteService: (id: string) => void;
}

const BillingView: React.FC<BillingViewProps> = ({ services, onSave, onAddService, onDeleteService }) => {
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [selectedItems, setSelectedItems] = useState<BillItem[]>([]);
  const [notes, setNotes] = useState('');

  // Service Creation State
  const [showAddService, setShowAddService] = useState(false);
  const [newServiceName, setNewServiceName] = useState('');
  const [newServiceRate, setNewServiceRate] = useState<number>(0);
  const [newServiceCategory, setNewServiceCategory] = useState<'sqft' | 'unit'>('sqft');

  const handleAddService = () => {
    if (!newServiceName) return;
    onAddService({
      id: Math.random().toString(36).substr(2, 9),
      name: newServiceName,
      defaultRate: newServiceRate,
      category: newServiceCategory
    });
    setNewServiceName('');
    setNewServiceRate(0);
    setShowAddService(false);
  };

  const addServiceToBill = (service: Service) => {
    const newItem: BillItem = {
      id: Math.random().toString(36).substr(2, 9),
      serviceId: service.id,
      serviceName: service.name,
      width: service.category === 'sqft' ? 1 : 0,
      height: service.category === 'sqft' ? 1 : 0,
      sqft: service.category === 'sqft' ? 1 : 0,
      rate: service.defaultRate,
      quantity: 1,
      amount: service.defaultRate,
    };
    setSelectedItems(prev => [...prev, newItem]);
  };

  const updateItem = (id: string, updates: Partial<BillItem>) => {
    setSelectedItems(prev => prev.map(item => {
      if (item.id !== id) return item;

      const updated = { ...item, ...updates };

      // Recalculate SQFT if width/height changed
      if (updates.width !== undefined || updates.height !== undefined) {
        updated.sqft = updated.width * updated.height;
      }

      // Recalculate Amount
      const service = services.find(s => s.id === updated.serviceId);
      if (service?.category === 'sqft') {
        updated.amount = updated.sqft * updated.rate * updated.quantity;
      } else {
        updated.amount = updated.rate * updated.quantity;
      }

      return updated;
    }));
  };

  const removeItem = (id: string) => {
    setSelectedItems(prev => prev.filter(i => i.id !== id));
  };

  const totalAmount = selectedItems.reduce((sum, item) => sum + item.amount, 0);

  const handleSave = () => {
    if (!customerName || selectedItems.length === 0) {
      alert("Please enter customer name and add at least one item.");
      return;
    }

    const newBill: Bill = {
      id: `INV-${Date.now()}`,
      customerName,
      customerPhone,
      date: new Date().toLocaleDateString(),
      time: new Date().toLocaleTimeString(),
      items: selectedItems,
      totalAmount,
      status: 'Pending',
      notes
    };

    onSave(newBill);
    setCustomerName('');
    setCustomerPhone('');
    setSelectedItems([]);
    setNotes('');
    alert("Bill saved successfully!");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
      {/* Services Sidebar */}
      <div className="lg:col-span-3 space-y-4">
        <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-center mb-4">
            <h3 className="font-bold text-gray-800 flex items-center">
              <i className="fas fa-list mr-2 text-orange-500"></i>
              Services
            </h3>
            <button 
              onClick={() => setShowAddService(!showAddService)}
              className="text-xs bg-orange-500 text-white px-2 py-1 rounded hover:bg-orange-600"
            >
              {showAddService ? 'Close' : '+ Add New'}
            </button>
          </div>

          {showAddService && (
            <div className="mb-4 p-3 bg-orange-50 rounded-lg border border-orange-100 space-y-2 animate-fade-in">
              <input 
                type="text" 
                placeholder="Service Name" 
                className="w-full p-2 text-xs border border-gray-200 rounded bg-white"
                value={newServiceName}
                onChange={e => setNewServiceName(e.target.value)}
              />
              <div className="flex gap-2">
                <input 
                  type="number" 
                  placeholder="Rate" 
                  className="w-1/2 p-2 text-xs border border-gray-200 rounded bg-white"
                  value={newServiceRate}
                  onChange={e => setNewServiceRate(parseFloat(e.target.value) || 0)}
                />
                <select 
                  className="w-1/2 p-2 text-xs border border-gray-200 rounded bg-white"
                  value={newServiceCategory}
                  onChange={e => setNewServiceCategory(e.target.value as 'sqft' | 'unit')}
                >
                  <option value="sqft">Per Sqft</option>
                  <option value="unit">Per Unit</option>
                </select>
              </div>
              <button 
                onClick={handleAddService}
                className="w-full py-2 bg-orange-500 text-white text-xs font-bold rounded hover:bg-orange-600"
              >
                Save Service
              </button>
            </div>
          )}

          <div className="grid grid-cols-1 gap-2 max-h-[500px] overflow-y-auto pr-1">
            {services.map(service => (
              <div key={service.id} className="flex group">
                <button
                  onClick={() => addServiceToBill(service)}
                  className="flex-1 text-left p-3 rounded-l-lg border border-gray-100 hover:border-orange-300 hover:bg-orange-50 transition-all flex justify-between items-center bg-white"
                >
                  <span className="text-sm font-medium text-gray-700">{service.name}</span>
                  <span className="text-[10px] bg-gray-100 px-1.5 py-0.5 rounded text-gray-500">₹{service.defaultRate}</span>
                </button>
                <button 
                  onClick={() => onDeleteService(service.id)}
                  className="px-2 border border-l-0 border-gray-100 rounded-r-lg bg-white text-gray-300 hover:text-red-500 hover:bg-red-50"
                >
                  <i className="fas fa-times text-xs"></i>
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Bill Editor */}
      <div className="lg:col-span-9 space-y-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
            <h2 className="text-xl font-bold text-gray-800">Billing Counter</h2>
            <div className="flex gap-4 w-full md:w-auto">
              <input
                type="text"
                placeholder="Customer Name"
                className="border-gray-200 border rounded-lg px-4 py-2 focus:ring-2 focus:ring-orange-500 focus:outline-none flex-1 bg-white"
                value={customerName}
                onChange={e => setCustomerName(e.target.value)}
              />
              <input
                type="text"
                placeholder="WhatsApp Number"
                className="border-gray-200 border rounded-lg px-4 py-2 focus:ring-2 focus:ring-orange-500 focus:outline-none flex-1 bg-white"
                value={customerPhone}
                onChange={e => setCustomerPhone(e.target.value)}
              />
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[600px]">
              <thead className="border-b border-gray-100 bg-gray-50">
                <tr>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase">Item Description</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase">Size (ft)</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase text-center">Total SQFT</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase text-center">Rate (₹)</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase text-center">Qty</th>
                  <th className="py-3 px-4 text-xs font-semibold text-gray-500 uppercase text-right">Total</th>
                  <th className="py-3 px-4"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {selectedItems.map(item => {
                  const s = services.find(sv => sv.id === item.serviceId);
                  const isSqft = s?.category === 'sqft';
                  return (
                    <tr key={item.id} className="hover:bg-gray-50 transition-colors">
                      <td className="py-4 px-4 font-medium text-gray-800">{item.serviceName}</td>
                      <td className="py-4 px-4">
                        {isSqft && (
                          <div className="flex items-center space-x-2">
                            <input 
                              type="number" 
                              className="w-14 border border-gray-200 rounded px-2 py-1 text-sm bg-white"
                              value={item.width}
                              onChange={e => updateItem(item.id, { width: parseFloat(e.target.value) || 0 })}
                            />
                            <span className="text-gray-400">×</span>
                            <input 
                              type="number" 
                              className="w-14 border border-gray-200 rounded px-2 py-1 text-sm bg-white"
                              value={item.height}
                              onChange={e => updateItem(item.id, { height: parseFloat(e.target.value) || 0 })}
                            />
                          </div>
                        )}
                      </td>
                      <td className="py-4 px-4 text-center text-sm text-gray-600">
                        {isSqft ? item.sqft.toFixed(2) : '1 Unit'}
                      </td>
                      <td className="py-4 px-4 text-center">
                        <input 
                          type="number" 
                          className="w-20 border border-gray-200 rounded px-2 py-1 text-sm text-center font-semibold text-orange-600 bg-white"
                          value={item.rate}
                          onChange={e => updateItem(item.id, { rate: parseFloat(e.target.value) || 0 })}
                        />
                      </td>
                      <td className="py-4 px-4 text-center">
                        <input 
                          type="number" 
                          className="w-16 border border-gray-200 rounded px-2 py-1 text-sm text-center font-bold bg-white"
                          value={item.quantity}
                          onChange={e => updateItem(item.id, { quantity: parseInt(e.target.value) || 1 })}
                        />
                      </td>
                      <td className="py-4 px-4 text-right font-bold text-gray-900">
                        ₹{item.amount.toLocaleString('en-IN')}
                      </td>
                      <td className="py-4 px-4 text-right">
                        <button 
                          onClick={() => removeItem(item.id)}
                          className="text-red-300 hover:text-red-500"
                        >
                          <i className="fas fa-trash"></i>
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          {selectedItems.length === 0 && (
            <div className="py-16 text-center text-gray-400">
              <i className="fas fa-hand-pointer text-4xl mb-3 block opacity-20"></i>
              Select services from the left to start billing
            </div>
          )}

          <div className="mt-8 pt-6 border-t border-gray-100 flex flex-col md:flex-row justify-between items-start gap-6">
            <div className="w-full md:w-1/2">
              <label className="block text-sm font-semibold text-gray-600 mb-2">Internal Remarks</label>
              <textarea
                className="w-full border border-gray-200 rounded-lg p-3 text-sm focus:ring-2 focus:ring-orange-500 focus:outline-none bg-white"
                rows={3}
                placeholder="Additional details for the job..."
                value={notes}
                onChange={e => setNotes(e.target.value)}
              />
            </div>
            <div className="w-full md:w-1/3 bg-gray-50 p-6 rounded-xl border border-gray-200">
              <div className="flex justify-between items-center mb-6">
                <span className="text-xl font-bold text-gray-800">Grand Total:</span>
                <span className="text-3xl font-black text-orange-600">₹{totalAmount.toLocaleString('en-IN')}</span>
              </div>
              <button 
                onClick={handleSave}
                disabled={selectedItems.length === 0}
                className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition-all ${
                  selectedItems.length > 0 ? 'bg-orange-500 hover:bg-orange-600 active:scale-95 shadow-orange-200' : 'bg-gray-300 cursor-not-allowed'
                }`}
              >
                SAVE INVOICE
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

