import React, { useState } from 'react';
import { Bill } from '../types';
import { generateReminderMessage } from '../services/geminiService';

interface HistoryViewProps {
  bills: Bill[];
  onUpdateStatus: (id: string, status: 'Pending' | 'Paid') => void;
  onDelete: (id: string) => void;
}

const HistoryView: React.FC<HistoryViewProps> = ({ bills, onUpdateStatus, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sendingId, setSendingId] = useState<string | null>(null);

  const filteredBills = bills.filter(bill => 
    bill.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (bill.customerPhone && bill.customerPhone.includes(searchTerm)) ||
    bill.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleWhatsApp = async (bill: Bill) => {
    if (!bill.customerPhone) {
      alert("No phone number found for this customer.");
      return;
    }

    setSendingId(bill.id);
    const message = await generateReminderMessage(bill);
    setSendingId(null);

    const encodedMsg = encodeURIComponent(message);
    const phone = bill.customerPhone.replace(/\D/g, '');
    window.open(`https://wa.me/${phone.startsWith('91') ? phone : '91' + phone}?text=${encodedMsg}`, '_blank');
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-bold text-gray-800">Billing Records</h2>
        <div className="relative w-full md:w-96">
          <i className="fas fa-search absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
          <input
            type="text"
            placeholder="Search customer, bill ID..."
            className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-orange-500 focus:outline-none bg-white"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left min-w-[700px]">
            <thead>
              <tr className="bg-gray-50 border-b border-gray-100">
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">Bill Details</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">Customer</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase text-right">Total Amount</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase text-center">Payment</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredBills.map(bill => (
                <tr key={bill.id} className="hover:bg-gray-50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="text-sm font-bold text-gray-900">{bill.id}</div>
                    <div className="text-xs text-gray-500">{bill.date} • {bill.time}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm font-semibold text-gray-800">{bill.customerName}</div>
                    <div className="text-xs text-gray-500 flex items-center mt-1">
                      <i className="fab fa-whatsapp text-green-500 mr-1"></i>
                      {bill.customerPhone || 'No Contact'}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="text-sm font-black text-gray-900">₹{bill.totalAmount.toLocaleString('en-IN')}</div>
                    <div className="text-xs text-gray-400">{bill.items.length} items</div>
                  </td>
                  <td className="px-6 py-4 text-center">
                    <button 
                      onClick={() => onUpdateStatus(bill.id, bill.status === 'Paid' ? 'Pending' : 'Paid')}
                      className={`px-3 py-1.5 rounded-full text-xs font-bold inline-flex items-center space-x-1 border transition-all ${
                        bill.status === 'Paid' 
                          ? 'bg-green-50 text-green-700 border-green-200 hover:bg-green-100' 
                          : 'bg-red-50 text-red-700 border-red-200 hover:bg-red-100'
                      }`}
                    >
                      <span className={`w-2 h-2 rounded-full ${bill.status === 'Paid' ? 'bg-green-500' : 'bg-red-500'}`}></span>
                      <span>{bill.status}</span>
                    </button>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end space-x-2">
                      {bill.status === 'Pending' && (
                        <button
                          onClick={() => handleWhatsApp(bill)}
                          disabled={sendingId === bill.id}
                          className="p-2 text-green-600 bg-green-50 hover:bg-green-100 rounded-lg transition-colors flex items-center gap-1 text-sm disabled:opacity-50"
                        >
                          <i className={`fab fa-whatsapp ${sendingId === bill.id ? 'animate-spin' : ''}`}></i>
                          <span className="hidden lg:inline">WhatsApp</span>
                        </button>
                      )}
                      <button
                        onClick={() => onDelete(bill.id)}
                        className="p-2 text-red-600 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
                      >
                        <i className="fas fa-trash-alt"></i>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filteredBills.length === 0 && (
          <div className="p-20 text-center text-gray-400">
            No records found.
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryView;

import React from 'react';
import { Bill } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface InsightsViewProps {
  bills: Bill[];
}

const InsightsView: React.FC<InsightsViewProps> = ({ bills }) => {
  const totalRevenue = bills.reduce((acc, bill) => acc + bill.totalAmount, 0);
  const totalPaid = bills.filter(b => b.status === 'Paid').reduce((acc, bill) => acc + bill.totalAmount, 0);
  const totalPending = bills.filter(b => b.status === 'Pending').reduce((acc, bill) => acc + bill.totalAmount, 0);

  // Group by date for simple chart (Last 7 Days)
  const last7Days = Array.from({ length: 7 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - i);
    return d.toLocaleDateString();
  }).reverse();

  const chartData = last7Days.map(date => {
    const dailyTotal = bills
      .filter(b => b.date === date)
      .reduce((sum, b) => sum + b.totalAmount, 0);
    return { date, amount: dailyTotal };
  });

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-50 text-blue-600 rounded-xl">
              <i className="fas fa-coins text-2xl"></i>
            </div>
            <div>
              <p className="text-sm text-gray-500 font-medium uppercase tracking-tight">Lifetime Revenue</p>
              <h4 className="text-2xl font-black text-gray-800">₹{totalRevenue.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-green-50 text-green-600 rounded-xl">
              <i className="fas fa-hand-holding-usd text-2xl"></i>
            </div>
            <div>
              <p className="text-sm text-gray-500 font-medium uppercase tracking-tight">Paid Collection</p>
              <h4 className="text-2xl font-black text-green-600">₹{totalPaid.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-red-50 text-red-600 rounded-xl">
              <i className="fas fa-clock text-2xl"></i>
            </div>
            <div>
              <p className="text-sm text-gray-500 font-medium uppercase tracking-tight">Pending Dues</p>
              <h4 className="text-2xl font-black text-red-600">₹{totalPending.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
        <h3 className="text-lg font-bold text-gray-800 mb-6 flex items-center">
          <i className="fas fa-chart-line mr-2 text-orange-500"></i>
          Daily Sales Performance (7 Days)
        </h3>
        <div className="h-[350px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
              <XAxis dataKey="date" tick={{fontSize: 10}} axisLine={false} tickLine={false} />
              <YAxis hide />
              <Tooltip 
                cursor={{fill: '#f8fafc'}}
                contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.05)'}}
              />
              <Bar dataKey="amount" fill="#f97316" radius={[8, 8, 0, 0]}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={index === chartData.length - 1 ? '#ea580c' : '#f97316'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-orange-50 p-6 rounded-2xl border border-orange-100">
        <h4 className="font-bold text-orange-800 mb-2">Summary Notice</h4>
        <p className="text-sm text-orange-700">
          This dashboard shows your recent financial activity. Use the WhatsApp reminder feature in "Bill History" to follow up on pending payments.
        </p>
      </div>
