};

export default InsightsView;

import { GoogleGenAI } from "@google/genai";
import { Bill } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateReminderMessage = async (bill: Bill): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a polite and professional WhatsApp reminder message for a customer named ${bill.customerName} who has a pending bill of ₹${bill.totalAmount} at "Shree Ganesh Flex & Advertising". The bill date was ${bill.date}. Keep it concise and include a call to action to settle the payment.`,
    });
    return response.text || `Hello ${bill.customerName}, this is a reminder regarding your pending payment of ₹${bill.totalAmount} at Shree Ganesh Flex. Please settle it at your earliest convenience. Thank you!`;
  } catch (error) {
    console.error("Gemini Error:", error);
    return `Hello ${bill.customerName}, reminder for your pending bill of ₹${bill.totalAmount}. - Shree Ganesh Flex`;
  }
};

export interface Service {
  id: string;
  name: string;
  defaultRate: number; // rate per sqft or per unit
  category: 'sqft' | 'unit';
}

export interface BillItem {
  id: string;
  serviceId: string;
  serviceName: string;
  width: number;
  height: number;
  sqft: number;
  rate: number;
  quantity: number;
  amount: number;
}

export interface Bill {
  id: string;
  customerName: string;
  customerPhone: string;
  date: string;
  time: string;
  items: BillItem[];
  totalAmount: number;
  status: 'Pending' | 'Paid';
  notes: string;
}

export interface Expense {
  id: string;
  amount: number;
  date: string;
  description: string;
}

export type AppView = 'Billing' | 'History' | 'Analytics';

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Bill, Service, AppView, Expense } from './types';
import { DEFAULT_SERVICES, APP_TITLE } from './constants';
import BillingView from './components/BillingView';
import HistoryView from './components/HistoryView';
import InsightsView from './components/InsightsView';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('Billing');
  const [bills, setBills] = useState<Bill[]>([]);
  const [services, setServices] = useState<Service[]>(DEFAULT_SERVICES);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  // Ref to track if initial data has been loaded from storage
  const isInitialLoadDone = useRef(false);

  // Load data from local storage on mount
  useEffect(() => {
    const savedBills = localStorage.getItem('sganesh_bills');
    const savedServices = localStorage.getItem('sganesh_services');
    const savedExpenses = localStorage.getItem('sganesh_expenses');

    if (savedBills) {
      try { setBills(JSON.parse(savedBills)); } catch (e) { console.error(e); }
    }
    if (savedServices) {
      try { setServices(JSON.parse(savedServices)); } catch (e) { console.error(e); }
    }
    if (savedExpenses) {
      try { setExpenses(JSON.parse(savedExpenses)); } catch (e) { console.error(e); }
    }

    isInitialLoadDone.current = true;
  }, []);

  // Save bills to local storage (only after initial load)
  useEffect(() => {
    if (isInitialLoadDone.current) {
      localStorage.setItem('sganesh_bills', JSON.stringify(bills));
    }
  }, [bills]);

  // Save services to local storage
  useEffect(() => {
    if (isInitialLoadDone.current) {
      localStorage.setItem('sganesh_services', JSON.stringify(services));
    }
  }, [services]);

  // Save expenses to local storage
  useEffect(() => {
    if (isInitialLoadDone.current) {
      localStorage.setItem('sganesh_expenses', JSON.stringify(expenses));
    }
  }, [expenses]);

  const addBill = useCallback((newBill: Bill) => {
    setBills(prev => [newBill, ...prev]);
  }, []);

  const updateBillStatus = useCallback((id: string, status: 'Pending' | 'Paid') => {
    setBills(prev => prev.map(bill => 
      bill.id === id ? { ...bill, status } : bill
    ));
  }, []);

  const deleteBill = useCallback((id: string) => {
    if (window.confirm("Are you sure you want to delete this bill?")) {
      setBills(prev => prev.filter(bill => bill.id !== id));
    }
  }, []);

  const addService = (service: Service) => {
    setServices(prev => [...prev, service]);
  };

  const deleteService = (id: string) => {
    if (window.confirm("Delete this service? It will no longer appear in the selection list.")) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const addExpense = (expense: Expense) => {
    setExpenses(prev => [expense, ...prev]);
  };

  const deleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const exportToCSV = () => {
    if (bills.length === 0) return alert("No data to export");
    const headers = ["ID", "Customer", "Phone", "Date", "Time", "Total", "Status", "Items"];
    const rows = bills.map(b => [
      b.id, b.customerName, b.customerPhone, b.date, b.time, b.totalAmount, b.status,
      b.items.map(i => `${i.serviceName}(${i.quantity})`).join('; ')
    ]);
    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", `billing_backup_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50">
      {/* Sidebar */}
      <nav className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col border-r border-slate-800">
        <div className="p-6 border-b border-slate-800">
          <h1 className="text-xl font-bold text-orange-400 leading-tight">
            {APP_TITLE}
          </h1>
          <p className="text-[10px] text-slate-500 mt-1 uppercase tracking-widest font-bold">Business Manager</p>
        </div>

        <div className="flex-1 py-4">
          <button 
            onClick={() => setView('Billing')}
            className={`w-full text-left px-6 py-4 flex items-center space-x-3 transition-all ${view === 'Billing' ? 'bg-orange-500 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-plus-circle w-6"></i>
            <span className="font-semibold">New Bill</span>
          </button>
          <button 
            onClick={() => setView('History')}
            className={`w-full text-left px-6 py-4 flex items-center space-x-3 transition-all ${view === 'History' ? 'bg-orange-500 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-receipt w-6"></i>
            <span className="font-semibold">Records</span>
          </button>
          <button 
            onClick={() => setView('Analytics')}
            className={`w-full text-left px-6 py-4 flex items-center space-x-3 transition-all ${view === 'Analytics' ? 'bg-orange-500 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-chart-pie w-6"></i>
            <span className="font-semibold">Profit & Loss</span>
          </button>
        </div>

        <div className="p-4 border-t border-slate-800 space-y-2 bg-slate-900/50">
          <button 
            onClick={exportToCSV}
            className="w-full bg-slate-800 hover:bg-slate-700 text-white py-2 px-4 rounded-lg text-xs flex items-center justify-center space-x-2 transition-colors border border-slate-700"
          >
            <i className="fas fa-database"></i>
            <span>Export Data (CSV)</span>
          </button>
          <div className="text-[9px] text-center text-slate-600 font-mono">
            PERSISTENT STORAGE ENABLED
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        <div className="p-4 md:p-10 max-w-7xl mx-auto">
          {view === 'Billing' && (
            <BillingView 
              services={services} 
              onSave={addBill} 
              onAddService={addService}
              onDeleteService={deleteService}
            />
          )}
          {view === 'History' && (
            <HistoryView 
              bills={bills} 
              onUpdateStatus={updateBillStatus} 
              onDelete={deleteBill} 
            />
          )}
          {view === 'Analytics' && (
            <InsightsView 
              bills={bills} 
              expenses={expenses}
              onAddExpense={addExpense}
              onDeleteExpense={deleteExpense}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Bill, Expense } from '../types';
import { 
  ComposedChart, 
  Bar, 
  Line, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer,
  Cell
} from 'recharts';

interface InsightsViewProps {
  bills: Bill[];
  expenses: Expense[];
  onAddExpense: (e: Expense) => void;
  onDeleteExpense: (id: string) => void;
}

const InsightsView: React.FC<InsightsViewProps> = ({ bills, expenses, onAddExpense, onDeleteExpense }) => {
  const [showAddExpense, setShowAddExpense] = useState(false);
  const [expAmount, setExpAmount] = useState<number>(0);
  const [expDesc, setExpDesc] = useState('');

  const handleAddExp = (e: React.FormEvent) => {
    e.preventDefault();
    if (!expAmount) return;
    onAddExpense({
      id: Math.random().toString(36).substr(2, 9),
      amount: expAmount,
      date: new Date().toLocaleDateString(),
      description: expDesc
    });
    setExpAmount(0);
    setExpDesc('');
    setShowAddExpense(false);
  };

  const totalRevenue = bills.reduce((acc, bill) => acc + bill.totalAmount, 0);
  const totalExpenses = expenses.reduce((acc, exp) => acc + exp.amount, 0);
  const netProfit = totalRevenue - totalExpenses;

  // Group by date for P&L chart (Last 7 Days)
  const last7Days = Array.from({ length: 7 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - i);
    return d.toLocaleDateString();
  }).reverse();

  const chartData = last7Days.map(date => {
    const dailyRevenue = bills
      .filter(b => b.date === date)
      .reduce((sum, b) => sum + b.totalAmount, 0);
    const dailyExpenses = expenses
      .filter(e => e.date === date)
      .reduce((sum, e) => sum + e.amount, 0);

    return { 
      date, 
      Revenue: dailyRevenue, 
      Expenses: dailyExpenses,
      Profit: dailyRevenue - dailyExpenses
    };
  });

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Header & Stats */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-2xl font-black text-gray-800 tracking-tight">Financial Overview</h2>
        <button 
          onClick={() => setShowAddExpense(!showAddExpense)}
          className="bg-red-500 hover:bg-red-600 text-white px-5 py-2.5 rounded-xl font-bold flex items-center shadow-lg shadow-red-100 transition-all"
        >
          <i className={`fas ${showAddExpense ? 'fa-times' : 'fa-minus-circle'} mr-2`}></i>
          {showAddExpense ? 'Cancel' : 'Record Expense'}
        </button>
      </div>

      {showAddExpense && (
        <form onSubmit={handleAddExp} className="bg-white p-6 rounded-2xl shadow-xl border border-red-100 flex flex-wrap gap-4 animate-slide-up">
          <div className="flex-1 min-w-[200px]">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Description</label>
            <input 
              type="text" 
              className="w-full bg-white border border-gray-200 rounded-lg p-2.5"
              placeholder="Rent, Raw material, etc."
              value={expDesc}
              onChange={e => setExpDesc(e.target.value)}
              required
            />
          </div>
          <div className="w-32">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Amount (₹)</label>
            <input 
              type="number" 
              className="w-full bg-white border border-gray-200 rounded-lg p-2.5 font-bold"
              value={expAmount}
              onChange={e => setExpAmount(parseFloat(e.target.value) || 0)}
              required
            />
          </div>
          <div className="flex items-end">
            <button type="submit" className="bg-slate-800 text-white px-6 py-2.5 rounded-lg font-bold">Save Expense</button>
          </div>
        </form>
      )}

      {/* Main KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-7 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-5">
            <div className="p-4 bg-green-50 text-green-600 rounded-2xl">
              <i className="fas fa-arrow-up text-2xl"></i>
            </div>
            <div>
              <p className="text-xs text-gray-400 font-black uppercase tracking-widest">Total Revenue</p>
              <h4 className="text-3xl font-black text-gray-800">₹{totalRevenue.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
        <div className="bg-white p-7 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-5">
            <div className="p-4 bg-red-50 text-red-600 rounded-2xl">
              <i className="fas fa-arrow-down text-2xl"></i>
            </div>
            <div>
              <p className="text-xs text-gray-400 font-black uppercase tracking-widest">Total Expenses</p>
              <h4 className="text-3xl font-black text-gray-800">₹{totalExpenses.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
        <div className={`p-7 rounded-3xl shadow-sm border ${netProfit >= 0 ? 'bg-orange-500 text-white border-orange-400' : 'bg-red-500 text-white border-red-400'}`}>
          <div className="flex items-center gap-5">
            <div className="p-4 bg-white/20 rounded-2xl">
              <i className="fas fa-wallet text-2xl"></i>
            </div>
            <div>
              <p className="text-xs opacity-80 font-black uppercase tracking-widest">Net Profit</p>
              <h4 className="text-3xl font-black">₹{netProfit.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
      </div>

      {/* Profit & Loss Chart */}
      <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
        <div className="flex justify-between items-center mb-10">
          <h3 className="text-xl font-black text-gray-800 flex items-center">
            <span className="w-2 h-8 bg-orange-500 rounded-full mr-3"></span>
            Daily Profit & Loss (7 Days)
          </h3>
          <div className="flex gap-4 text-xs font-bold text-gray-400">
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-green-400 rounded-sm"></span> Revenue</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-red-400 rounded-sm"></span> Expenses</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-orange-500 rounded-full"></span> Net Profit</span>
          </div>
        </div>
        <div className="h-[450px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
              <XAxis dataKey="date" tick={{fontSize: 10, fill: '#94a3b8'}} axisLine={false} tickLine={false} dy={10} />
              <YAxis tick={{fontSize: 10, fill: '#94a3b8'}} axisLine={false} tickLine={false} dx={-10} />
              <Tooltip 
                cursor={{fill: '#f8fafc'}}
                contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.1)', padding: '12px'}}
              />
              <Legend verticalAlign="top" height={36}/>
              <Bar dataKey="Revenue" fill="#4ade80" radius={[6, 6, 0, 0]} barSize={40} />
              <Bar dataKey="Expenses" fill="#f87171" radius={[6, 6, 0, 0]} barSize={40} />
              <Area type="monotone" dataKey="Profit" fill="#fff7ed" stroke="none" />
              <Line type="monotone" dataKey="Profit" stroke="#f97316" strokeWidth={4} dot={{r: 6, fill: '#f97316', strokeWidth: 2, stroke: '#fff'}} />
