import React, { useState } from 'react';
import { Bill, BillItem, Service } from '../types';

interface BillingViewProps {
  services: Service[];
  onSave: (bill: Bill) => void;
  onAddService: (service: Service) => void;
  onDeleteService: (id: string) => void;
}

const BillingView: React.FC<BillingViewProps> = ({ services, onSave, onAddService, onDeleteService }) => {
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [selectedItems, setSelectedItems] = useState<BillItem[]>([]);
  const [notes, setNotes] = useState('');

  // Service Creation State
  const [showAddService, setShowAddService] = useState(false);
  const [newServiceName, setNewServiceName] = useState('');
  const [newServiceRate, setNewServiceRate] = useState<number>(0);
  const [newServiceCategory, setNewServiceCategory] = useState<'sqft' | 'unit'>('sqft');

  const handleAddService = () => {
    if (!newServiceName) return;
    onAddService({
      id: Math.random().toString(36).substr(2, 9),
      name: newServiceName,
      defaultRate: newServiceRate,
      category: newServiceCategory
    });
    setNewServiceName('');
    setNewServiceRate(0);
    setShowAddService(false);
  };

  const addServiceToBill = (service: Service) => {
    const newItem: BillItem = {
      id: Math.random().toString(36).substr(2, 9),
      serviceId: service.id,
      serviceName: service.name,
      width: service.category === 'sqft' ? 1 : 0,
      height: service.category === 'sqft' ? 1 : 0,
      sqft: service.category === 'sqft' ? 1 : 0,
      rate: service.defaultRate,
      quantity: 1,
      amount: service.defaultRate,
    };
    setSelectedItems(prev => [...prev, newItem]);
  };

  const updateItem = (id: string, updates: Partial<BillItem>) => {
    setSelectedItems(prev => prev.map(item => {
      if (item.id !== id) return item;
      const updated = { ...item, ...updates };
      if (updates.width !== undefined || updates.height !== undefined) {
        updated.sqft = updated.width * updated.height;
      }
      const service = services.find(s => s.id === updated.serviceId);
      if (service?.category === 'sqft') {
        updated.amount = updated.sqft * updated.rate * updated.quantity;
      } else {
        updated.amount = updated.rate * updated.quantity;
      }
      return updated;
    }));
  };

  const removeItem = (id: string) => {
    setSelectedItems(prev => prev.filter(i => i.id !== id));
  };

  const totalAmount = selectedItems.reduce((sum, item) => sum + item.amount, 0);

  const handleSave = () => {
    if (!customerName || selectedItems.length === 0) {
      alert("Please enter customer name and add at least one item.");
      return;
    }

    const newBill: Bill = {
      id: `INV-${Date.now()}`,
      customerName,
      customerPhone,
      date: new Date().toLocaleDateString(),
      time: new Date().toLocaleTimeString(),
      items: selectedItems,
      totalAmount,
      status: 'Pending',
      notes
    };

    onSave(newBill);
    setCustomerName('');
    setCustomerPhone('');
    setSelectedItems([]);
    setNotes('');
    alert("Bill generated and saved permanently to storage!");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* Sidebar - Services */}
      <div className="lg:col-span-3 space-y-5">
        <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-black text-gray-800 text-sm uppercase tracking-wider flex items-center">
              <span className="w-1.5 h-4 bg-orange-500 rounded-full mr-2"></span>
              Service List
            </h3>
            <button 
              onClick={() => setShowAddService(!showAddService)}
              className="w-8 h-8 flex items-center justify-center bg-orange-500 text-white rounded-full hover:bg-orange-600 shadow-md shadow-orange-100"
            >
              <i className={`fas ${showAddService ? 'fa-times' : 'fa-plus'} text-xs`}></i>
            </button>
          </div>

          {showAddService && (
            <div className="mb-6 p-4 bg-orange-50 rounded-2xl border border-orange-100 space-y-3 animate-fade-in">
              <input 
                type="text" 
                placeholder="Job Name (e.g. Star Flex)" 
                className="w-full p-2.5 text-sm border border-gray-200 rounded-xl bg-white focus:ring-2 focus:ring-orange-500 outline-none"
                value={newServiceName}
                onChange={e => setNewServiceName(e.target.value)}
              />
              <div className="flex gap-2">
                <input 
                  type="number" 
                  placeholder="Rate" 
                  className="w-1/2 p-2.5 text-sm border border-gray-200 rounded-xl bg-white focus:ring-2 focus:ring-orange-500 outline-none"
                  value={newServiceRate}
                  onChange={e => setNewServiceRate(parseFloat(e.target.value) || 0)}
                />
                <select 
                  className="w-1/2 p-2.5 text-sm border border-gray-200 rounded-xl bg-white outline-none"
                  value={newServiceCategory}
                  onChange={e => setNewServiceCategory(e.target.value as 'sqft' | 'unit')}
                >
                  <option value="sqft">Sqft</option>
                  <option value="unit">Unit</option>
                </select>
              </div>
              <button 
                onClick={handleAddService}
                className="w-full py-3 bg-slate-900 text-white text-xs font-black rounded-xl hover:bg-black transition-colors"
              >
                CREATE SERVICE
              </button>
            </div>
          )}

          <div className="grid grid-cols-1 gap-2.5 max-h-[60vh] overflow-y-auto pr-1 thin-scrollbar">
            {services.map(service => (
              <div key={service.id} className="flex group relative overflow-hidden rounded-2xl border border-gray-100 hover:border-orange-200 transition-all">
                <button
                  onClick={() => addServiceToBill(service)}
                  className="flex-1 text-left p-4 flex flex-col bg-white hover:bg-orange-50/50"
                >
                  <span className="text-sm font-bold text-gray-700 truncate mb-1">{service.name}</span>
                  <span className="text-[10px] font-black text-orange-600 bg-orange-100 w-fit px-2 py-0.5 rounded-full">₹{service.defaultRate} / {service.category}</span>
                </button>
                <button 
                  onClick={() => onDeleteService(service.id)}
                  className="px-3 text-gray-300 hover:text-red-500 hover:bg-red-50 transition-colors border-l border-gray-50"
                >
                  <i className="fas fa-trash-alt text-[10px]"></i>
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Main Counter */}
      <div className="lg:col-span-9 space-y-6">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-10 pb-6 border-b border-gray-50">
            <div className="flex-1 space-y-4">
              <h2 className="text-2xl font-black text-gray-800 tracking-tight">Invoice Generator</h2>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Customer Details</label>
                  <input
                    type="text"
                    placeholder="Enter Full Name"
                    className="w-full border-2 border-gray-100 rounded-2xl px-5 py-3.5 focus:border-orange-500 focus:ring-0 outline-none bg-white transition-all text-gray-800 font-bold"
                    value={customerName}
                    onChange={e => setCustomerName(e.target.value)}
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">WhatsApp / Contact</label>
                  <input
                    type="text"
                    placeholder="Mobile Number"
                    className="w-full border-2 border-gray-100 rounded-2xl px-5 py-3.5 focus:border-orange-500 focus:ring-0 outline-none bg-white transition-all text-gray-800 font-bold"
                    value={customerPhone}
                    onChange={e => setCustomerPhone(e.target.value)}
                  />
                </div>
              </div>
            </div>
            <div className="flex-shrink-0 text-right md:mb-1">
              <div className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Date & Time</div>
              <div className="text-gray-500 font-mono text-sm">{new Date().toLocaleDateString()} • {new Date().toLocaleTimeString()}</div>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[700px]">
              <thead>
                <tr className="text-[10px] font-black text-gray-400 uppercase tracking-widest border-b-2 border-gray-50">
                  <th className="py-4 px-2">Job Description</th>
                  <th className="py-4 px-2">Size (ft)</th>
                  <th className="py-4 px-2 text-center">Total Area</th>
                  <th className="py-4 px-2 text-center">Rate (₹)</th>
                  <th className="py-4 px-2 text-center">Qty</th>
                  <th className="py-4 px-2 text-right">Subtotal</th>
                  <th className="py-4 px-2"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50/50">
                {selectedItems.map(item => {
                  const s = services.find(sv => sv.id === item.serviceId);
                  const isSqft = s?.category === 'sqft';
                  return (
                    <tr key={item.id} className="hover:bg-gray-50/30 transition-colors animate-fade-in">
                      <td className="py-5 px-2">
                        <div className="font-black text-gray-800">{item.serviceName}</div>
                        <div className="text-[10px] text-gray-400 font-bold">{isSqft ? 'SQUARE FOOTAGE JOB' : 'UNIT BASED JOB'}</div>
                      </td>
                      <td className="py-5 px-2">
                        {isSqft && (
                          <div className="flex items-center gap-1.5">
                            <input 
                              type="number" 
                              className="w-16 border-2 border-gray-100 rounded-xl px-2 py-1.5 text-xs font-bold bg-white focus:border-orange-500 outline-none"
                              value={item.width}
                              onChange={e => updateItem(item.id, { width: parseFloat(e.target.value) || 0 })}
                            />
                            <span className="text-gray-300 font-black">×</span>
                            <input 
                              type="number" 
                              className="w-16 border-2 border-gray-100 rounded-xl px-2 py-1.5 text-xs font-bold bg-white focus:border-orange-500 outline-none"
                              value={item.height}
                              onChange={e => updateItem(item.id, { height: parseFloat(e.target.value) || 0 })}
                            />
                          </div>
                        )}
                      </td>
                      <td className="py-5 px-2 text-center">
                        <span className="text-xs font-black text-slate-500 bg-slate-100 px-2 py-1 rounded-lg">
                          {isSqft ? `${item.sqft.toFixed(2)} ft²` : 'Fixed'}
                        </span>
                      </td>
                      <td className="py-5 px-2 text-center">
                        <input 
                          type="number" 
                          className="w-24 border-2 border-orange-100 rounded-xl px-2 py-1.5 text-sm text-center font-black text-orange-600 bg-white focus:border-orange-500 outline-none"
                          value={item.rate}
                          onChange={e => updateItem(item.id, { rate: parseFloat(e.target.value) || 0 })}
                        />
                      </td>
                      <td className="py-5 px-2 text-center">
                        <input 
                          type="number" 
                          className="w-16 border-2 border-gray-100 rounded-xl px-2 py-1.5 text-sm text-center font-black bg-white focus:border-orange-500 outline-none"
                          value={item.quantity}
                          onChange={e => updateItem(item.id, { quantity: parseInt(e.target.value) || 1 })}
                        />
                      </td>
                      <td className="py-5 px-2 text-right font-black text-gray-900 text-lg">
                        ₹{item.amount.toLocaleString('en-IN')}
                      </td>
                      <td className="py-5 px-2 text-right">
                        <button 
                          onClick={() => removeItem(item.id)}
                          className="w-8 h-8 flex items-center justify-center text-red-200 hover:text-red-500 hover:bg-red-50 rounded-full transition-all"
                        >
                          <i className="fas fa-times"></i>
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          {selectedItems.length === 0 && (
            <div className="py-24 text-center">
              <div className="inline-flex items-center justify-center w-20 h-20 bg-gray-50 rounded-full mb-6">
                <i className="fas fa-plus text-gray-200 text-2xl"></i>
              </div>
              <h4 className="text-gray-400 font-black uppercase tracking-widest text-sm">Waiting for selection...</h4>
              <p className="text-gray-300 text-xs mt-2">Pick a service from the sidebar to begin</p>
            </div>
          )}

          <div className="mt-12 pt-10 border-t-2 border-gray-50 grid grid-cols-1 md:grid-cols-2 gap-10">
            <div className="space-y-4">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Job Instructions / Notes</label>
              <textarea
                className="w-full border-2 border-gray-100 rounded-3xl p-5 text-sm bg-white focus:border-orange-500 outline-none font-medium text-gray-600 min-h-[120px] transition-all"
                placeholder="Write any specific delivery dates or finishing instructions here..."
                value={notes}
                onChange={e => setNotes(e.target.value)}
              />
            </div>
            <div className="bg-slate-900 p-8 rounded-[40px] text-white flex flex-col justify-between shadow-2xl shadow-slate-200">
              <div className="flex justify-between items-center mb-8">
                <span className="text-xs font-black uppercase tracking-widest opacity-50">Grand Total Payable</span>
                <span className="text-4xl font-black text-orange-400">₹{totalAmount.toLocaleString('en-IN')}</span>
              </div>
              <button 
                onClick={handleSave}
                disabled={selectedItems.length === 0}
                className={`w-full py-5 rounded-2xl font-black text-sm uppercase tracking-widest transition-all ${
                  selectedItems.length > 0 
                    ? 'bg-orange-500 hover:bg-orange-600 text-white shadow-lg shadow-orange-900/20 active:scale-[0.98]' 
                    : 'bg-slate-800 text-slate-700 cursor-not-allowed border border-slate-700'
                }`}
              >
                CONFIRM & SAVE BILL
              </button>
              <div className="mt-4 text-[9px] text-center font-bold text-slate-500 uppercase tracking-tighter">
                AUTO-SAVED TO PERSISTENT CLOUD STORAGE
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

