import React, { useState } from 'react';
import { Bill, Expense } from '../types';
import { 
  ComposedChart, 
  Bar, 
  Line, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer,
  Cell
} from 'recharts';

interface InsightsViewProps {
  bills: Bill[];
  expenses: Expense[];
  onAddExpense: (e: Expense) => void;
  onDeleteExpense: (id: string) => void;
}

const InsightsView: React.FC<InsightsViewProps> = ({ bills, expenses, onAddExpense, onDeleteExpense }) => {
  const [showAddExpense, setShowAddExpense] = useState(false);
  const [expAmount, setExpAmount] = useState<number>(0);
  const [expDesc, setExpDesc] = useState('');

  const handleAddExp = (e: React.FormEvent) => {
    e.preventDefault();
    if (!expAmount) return;
    onAddExpense({
      id: Math.random().toString(36).substr(2, 9),
      amount: expAmount,
      date: new Date().toLocaleDateString(),
      description: expDesc
    });
    setExpAmount(0);
    setExpDesc('');
    setShowAddExpense(false);
  };

  const totalRevenue = bills.reduce((acc, bill) => acc + bill.totalAmount, 0);
  const totalExpenses = expenses.reduce((acc, exp) => acc + exp.amount, 0);
  const totalPending = bills
    .filter(b => b.status === 'Pending')
    .reduce((acc, bill) => acc + bill.totalAmount, 0);
  const netProfit = totalRevenue - totalExpenses;

  // Group by date for P&L chart (Last 7 Days)
  const last7Days = Array.from({ length: 7 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - i);
    return d.toLocaleDateString();
  }).reverse();

  const chartData = last7Days.map(date => {
    const dailyRevenue = bills
      .filter(b => b.date === date)
      .reduce((sum, b) => sum + b.totalAmount, 0);
    const dailyExpenses = expenses
      .filter(e => e.date === date)
      .reduce((sum, e) => sum + e.amount, 0);

    return { 
      date, 
      Revenue: dailyRevenue, 
      Expenses: dailyExpenses,
      Profit: dailyRevenue - dailyExpenses
    };
  });

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Header & Stats */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-2xl font-black text-gray-800 tracking-tight">Financial Overview</h2>
        <button 
          onClick={() => setShowAddExpense(!showAddExpense)}
          className="bg-red-500 hover:bg-red-600 text-white px-5 py-2.5 rounded-xl font-bold flex items-center shadow-lg shadow-red-100 transition-all"
        >
          <i className={`fas ${showAddExpense ? 'fa-times' : 'fa-minus-circle'} mr-2`}></i>
          {showAddExpense ? 'Cancel' : 'Record Expense'}
        </button>
      </div>

      {showAddExpense && (
        <form onSubmit={handleAddExp} className="bg-white p-6 rounded-2xl shadow-xl border border-red-100 flex flex-wrap gap-4 animate-slide-up">
          <div className="flex-1 min-w-[200px]">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Description</label>
            <input 
              type="text" 
              className="w-full bg-white border border-gray-200 rounded-lg p-2.5"
              placeholder="Rent, Raw material, etc."
              value={expDesc}
              onChange={e => setExpDesc(e.target.value)}
              required
            />
          </div>
          <div className="w-32">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Amount (₹)</label>
            <input 
              type="number" 
              className="w-full bg-white border border-gray-200 rounded-lg p-2.5 font-bold"
              value={expAmount}
              onChange={e => setExpAmount(parseFloat(e.target.value) || 0)}
              required
            />
          </div>
          <div className="flex items-end">
            <button type="submit" className="bg-slate-800 text-white px-6 py-2.5 rounded-lg font-bold">Save Expense</button>
          </div>
        </form>
      )}

      {/* Main KPI Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-green-50 text-green-600 rounded-2xl">
              <i className="fas fa-arrow-up text-xl"></i>
            </div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Total Revenue</p>
              <h4 className="text-xl font-black text-gray-800">₹{totalRevenue.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-red-50 text-red-600 rounded-2xl">
              <i className="fas fa-arrow-down text-xl"></i>
            </div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Total Expenses</p>
              <h4 className="text-xl font-black text-gray-800">₹{totalExpenses.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
