import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Bill, Service, AppView, Expense, PersonalTransaction, SubscriptionData } from './types';
import { DEFAULT_SERVICES, APP_TITLE } from './constants';
import BillingView from './components/BillingView';
import HistoryView from './components/HistoryView';
import InsightsView from './components/InsightsView';
import PersonalView from './components/PersonalView';
import LockOverlay from './components/LockOverlay';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('Billing');
  const [bills, setBills] = useState<Bill[]>([]);
  const [services, setServices] = useState<Service[]>(DEFAULT_SERVICES);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [personalTransactions, setPersonalTransactions] = useState<PersonalTransaction[]>([]);
  const [subscription, setSubscription] = useState<SubscriptionData>({
    installDate: new Date().toISOString(),
    isActivated: false
  });

  const isInitialLoadDone = useRef(false);

  // Load data from local storage on mount
  useEffect(() => {
    const savedBills = localStorage.getItem('sganesh_bills');
    const savedServices = localStorage.getItem('sganesh_services');
    const savedExpenses = localStorage.getItem('sganesh_expenses');
    const savedPersonal = localStorage.getItem('sganesh_personal');
    const savedSub = localStorage.getItem('sganesh_subscription');

    if (savedBills) {
      try { setBills(JSON.parse(savedBills)); } catch (e) { console.error(e); }
    }
    if (savedServices) {
      try { setServices(JSON.parse(savedServices)); } catch (e) { console.error(e); }
    }
    if (savedExpenses) {
      try { setExpenses(JSON.parse(savedExpenses)); } catch (e) { console.error(e); }
    }
    if (savedPersonal) {
      try { setPersonalTransactions(JSON.parse(savedPersonal)); } catch (e) { console.error(e); }
    }
    if (savedSub) {
      try { 
        setSubscription(JSON.parse(savedSub)); 
      } catch (e) { console.error(e); }
    } else {
      const initialSub = { installDate: new Date().toISOString(), isActivated: false };
      setSubscription(initialSub);
      localStorage.setItem('sganesh_subscription', JSON.stringify(initialSub));
    }

    isInitialLoadDone.current = true;
  }, []);

  // Save to local storage
  useEffect(() => {
    if (isInitialLoadDone.current) {
      localStorage.setItem('sganesh_bills', JSON.stringify(bills));
      localStorage.setItem('sganesh_services', JSON.stringify(services));
      localStorage.setItem('sganesh_expenses', JSON.stringify(expenses));
      localStorage.setItem('sganesh_personal', JSON.stringify(personalTransactions));
      localStorage.setItem('sganesh_subscription', JSON.stringify(subscription));
    }
  }, [bills, services, expenses, personalTransactions, subscription]);

  // Subscription Calculations
  // Logic: 30 days from either installDate (first time) or lastActivationDate (recurring)
  const baseDate = subscription.lastActivationDate 
    ? new Date(subscription.lastActivationDate) 
    : new Date(subscription.installDate);

  const currentDate = new Date();
  const diffTime = Math.abs(currentDate.getTime() - baseDate.getTime());
  const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

  // Set TRIAL_LIMIT_DAYS to 30 for production. Set to 0 for DEMO/Testing.
  const TRIAL_LIMIT_DAYS = 0; 
  const daysLeft = Math.max(0, TRIAL_LIMIT_DAYS - diffDays);

  // A lock occurs if trial is over AND it hasn't been activated for THIS cycle.
  // When a user activates, we set isActivated=true and update lastActivationDate.
  // We need to detect when the 30 days pass AGAIN after activation.
  const isCurrentlyInLockPhase = diffDays >= TRIAL_LIMIT_DAYS;
  const isLocked = isCurrentlyInLockPhase && !subscription.isActivated;

  // Handle Dynamic Key Generation
  useEffect(() => {
    if (isLocked && !subscription.pendingKey) {
      const randomKey = `SG-${Math.random().toString(36).substring(2, 8).toUpperCase()}`;
      setSubscription(prev => ({ ...prev, pendingKey: randomKey }));
    }
  }, [isLocked, subscription.pendingKey]);

  // Reset activation status if a new cycle starts
  useEffect(() => {
    if (!isCurrentlyInLockPhase && subscription.isActivated === false) {
      // This case handles a fresh installation window
    } else if (isCurrentlyInLockPhase && subscription.isActivated) {
      // Logic for recurring expiry:
      // If activated previously but the 30 days have passed since THAT activation,
      // we need to expire it again.
      const activationDate = subscription.lastActivationDate ? new Date(subscription.lastActivationDate) : null;
      if (activationDate) {
        const timeSinceActivation = Math.abs(currentDate.getTime() - activationDate.getTime());
        const daysSinceActivation = Math.floor(timeSinceActivation / (1000 * 60 * 60 * 24));
        if (daysSinceActivation >= 30) {
           setSubscription(prev => ({ ...prev, isActivated: false, pendingKey: undefined }));
        }
      }
    }
  }, [isCurrentlyInLockPhase, subscription.isActivated, subscription.lastActivationDate]);

  const handleActivate = (success: boolean) => {
    if (success) {
      setSubscription(prev => ({ 
        ...prev, 
        isActivated: true, 
        lastActivationDate: new Date().toISOString(),
        pendingKey: undefined // Clear key so next time a new one is made
      }));
    }
  };

  const addBill = useCallback((newBill: Bill) => {
    setBills(prev => [newBill, ...prev]);
  }, []);

  const updateBillStatus = useCallback((id: string, status: 'Pending' | 'Paid') => {
    setBills(prev => prev.map(bill => bill.id === id ? { ...bill, status } : bill));
  }, []);

  const deleteBill = useCallback((id: string) => {
    if (window.confirm("Are you sure you want to delete this bill?")) {
      setBills(prev => prev.filter(bill => bill.id !== id));
    }
  }, []);

  const addService = (service: Service) => {
    setServices(prev => [...prev, service]);
  };

  const deleteService = (id: string) => {
    if (window.confirm("Delete this service?")) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const addExpense = (expense: Expense) => {
    setExpenses(prev => [expense, ...prev]);
  };

  const deleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const addPersonalTransaction = (pt: PersonalTransaction) => {
    setPersonalTransactions(prev => [pt, ...prev]);
  };

  const deletePersonalTransaction = (id: string) => {
    setPersonalTransactions(prev => prev.filter(p => p.id !== id));
  };

  const exportToCSV = () => {
    if (bills.length === 0) return alert("No data to export");
    const headers = ["ID", "Customer", "Phone", "Date", "Time", "Total", "Status", "Items"];
    const rows = bills.map(b => [
      b.id, b.customerName, b.customerPhone, b.date, b.time, b.totalAmount, b.status,
      b.items.map(i => `${i.serviceName}(${i.quantity})`).join('; ')
    ]);
    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", `billing_backup_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50 overflow-hidden relative pb-10">
      <style>{`
        @keyframes slide {
          from { transform: translateX(100%); }
          to { transform: translateX(-100%); }
        }
        .sliding-text {
          animation: slide 20s linear infinite;
        }
      `}</style>

      {isLocked && (
        <LockOverlay 
          onActivate={handleActivate} 
          pendingKey={subscription.pendingKey || 'SG-GENERATING'} 
        />
      )}

      {/* Sidebar */}
      <nav className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col border-r border-slate-800 z-10">
        <div className="p-6 border-b border-slate-800">
          <h1 className="text-xl font-bold text-orange-400 leading-tight">
            {APP_TITLE}
          </h1>
          <p className="text-[10px] text-slate-500 mt-1 uppercase tracking-widest font-bold">Business Manager</p>
        </div>

        <div className="flex-1 py-4">
          <button 
            onClick={() => setView('Billing')}
            className={`w-full text-left px-6 py-4 flex items-center space-x-3 transition-all ${view === 'Billing' ? 'bg-orange-500 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-plus-circle w-6"></i>
            <span className="font-semibold">New Bill</span>
          </button>
          <button 
            onClick={() => setView('History')}
            className={`w-full text-left px-6 py-4 flex items-center space-x-3 transition-all ${view === 'History' ? 'bg-orange-500 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-receipt w-6"></i>
            <span className="font-semibold">Records</span>
          </button>
          <button 
            onClick={() => setView('Analytics')}
            className={`w-full text-left px-6 py-4 flex items-center space-x-3 transition-all ${view === 'Analytics' ? 'bg-orange-500 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-chart-pie w-6"></i>
            <span className="font-semibold">Profit & Loss</span>
          </button>
          <button 
            onClick={() => setView('Personal')}
            className={`w-full text-left px-6 py-4 flex items-center space-x-3 transition-all ${view === 'Personal' ? 'bg-orange-500 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-300'}`}
          >
            <i className="fas fa-user-tag w-6"></i>
            <span className="font-semibold">Personal Activity</span>
          </button>
        </div>

        <div className="p-4 border-t border-slate-800 space-y-2 bg-slate-900/50">
          {!subscription.isActivated && (
            <div className="mb-4 bg-orange-500/10 border border-orange-500/20 p-3 rounded-lg">
              <p className="text-[10px] font-black uppercase text-orange-400">Subscription Status</p>
              <p className="text-xs font-bold text-white mt-1">{daysLeft} Days Remaining</p>
              <div className="w-full bg-slate-800 h-1 mt-2 rounded-full overflow-hidden">
                <div className="bg-orange-50 h-full" style={{ width: `${((daysLeft / 30) || 0) * 100}%` }}></div>
              </div>
            </div>
          )}

          <button 
            onClick={exportToCSV}
            className="w-full bg-slate-800 hover:bg-slate-700 text-white py-2 px-4 rounded-lg text-xs flex items-center justify-center space-x-2 transition-colors border border-slate-700"
          >
            <i className="fas fa-database"></i>
            <span>Export Data (CSV)</span>
          </button>
          <div className="text-[9px] text-center text-slate-600 font-mono">
            {subscription.isActivated ? 'VERSION: PREMIUM ACTIVATED' : 'VERSION: TRIAL ACTIVE'}
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        <div className="p-4 md:p-10 max-w-7xl mx-auto mb-16">
          {view === 'Billing' && (
            <BillingView 
              services={services} 
              onSave={addBill} 
              onAddService={addService}
              onDeleteService={deleteService}
            />
          )}
          {view === 'History' && (
            <HistoryView 
              bills={bills} 
              onUpdateStatus={updateBillStatus} 
              onDelete={deleteBill} 
            />
          )}
          {view === 'Analytics' && (
            <InsightsView 
              bills={bills} 
              expenses={expenses}
              onAddExpense={addExpense}
              onDeleteExpense={deleteExpense}
            />
          )}
          {view === 'Personal' && (
            <PersonalView
              transactions={personalTransactions}
              onAdd={addPersonalTransaction}
              onDelete={deletePersonalTransaction}
            />
          )}
        </div>
      </main>

      {/* Sliding credit footer */}
      <div className="fixed bottom-0 left-0 w-full bg-white border-t border-gray-200 h-10 flex items-center overflow-hidden z-20">
        <div className="sliding-text whitespace-nowrap text-sm font-bold text-gray-500">
          Software Made By <a href="https://instagram.com/theaniketchoudhari" target="_blank" rel="noopener noreferrer" className="text-orange-500 hover:text-orange-600 px-2 transition-colors">@theaniketchoudhari</a> • Shree Ganesh Flex & Advertising Management System • Permanent Data Persistence Active • High Performance Billing Engine
        </div>
      </div>
    </div>
  );
};

export default App;

