    const rows = bills.map(b => [
      b.id, b.customerName, b.customerPhone, b.date, b.time, b.totalAmount, b.status,
      b.items.map(i => `${i.serviceName}(${i.quantity})`).join('; ')
    ]);
    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", `billing_backup_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50 overflow-hidden relative pb-10">
      <style>{`
        @keyframes slide {
          from { transform: translateX(100%); }
          to { transform: translateX(-100%); }
        }
        .sliding-text {
          animation: slide 20s linear infinite;
        }
      `}</style>

      {isLocked && (
        <LockOverlay 
          onActivate={handleActivate} 
          pendingKey={subscription.pendingKey || 'SG-WAITING'} 
        />
      )}

      {/* Sidebar */}
      <nav className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col border-r border-slate-800 z-10">
        <div className="p-6 border-b border-slate-800">
