        </div>

        <div className="flex-1 py-4">
          <button 
            onClick={() => setView('Billing')}
            className={`w-full text-left px-6 py-4 flex items-center space-x-3 transition-all ${view === 'Billing' ? 'bg-orange-500 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-300'}`}
          >
