import { Bill, Service, AppView, Expense, PersonalTransaction, SubscriptionData } from './types';
import { DEFAULT_SERVICES, APP_TITLE } from './constants';
import BillingView from './components/BillingView';
import HistoryView from './components/HistoryView';
import InsightsView from './components/InsightsView';
import PersonalView from './components/PersonalView';
import LockOverlay from './components/LockOverlay';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('Billing');
  const [bills, setBills] = useState<Bill[]>([]);
  const [services, setServices] = useState<Service[]>(DEFAULT_SERVICES);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [personalTransactions, setPersonalTransactions] = useState<PersonalTransaction[]>([]);
  const [subscription, setSubscription] = useState<SubscriptionData>({
    installDate: new Date().toISOString(),
    isActivated: false
  });

  const [lastSync, setLastSync] = useState<string>(new Date().toLocaleTimeString());
  const isInitialLoadDone = useRef(false);

  // --- INDUSTRIAL STORAGE ENGINE ---
  useEffect(() => {
    console.log("Initializing Shree Ganesh Persistence Engine...");

    const loadData = () => {
      try {
        const savedBills = localStorage.getItem('sganesh_bills');
        const savedServices = localStorage.getItem('sganesh_services');
        const savedExpenses = localStorage.getItem('sganesh_expenses');
        const savedPersonal = localStorage.getItem('sganesh_personal');
        const savedSub = localStorage.getItem('sganesh_subscription');

        if (savedBills) setBills(JSON.parse(savedBills));
        if (savedServices) setServices(JSON.parse(savedServices));
        if (savedExpenses) setExpenses(JSON.parse(savedExpenses));
        if (savedPersonal) setPersonalTransactions(JSON.parse(savedPersonal));

        if (savedSub) {
          setSubscription(JSON.parse(savedSub));
        } else {
          const initialSub = { installDate: new Date().toISOString(), isActivated: false };
          setSubscription(initialSub);
          localStorage.setItem('sganesh_subscription', JSON.stringify(initialSub));
        }

        isInitialLoadDone.current = true;
        console.log("Data Restoration Successful.");
      } catch (error) {
        console.error("Storage Restoration Error:", error);
        alert("Critical: Could not load local data. Please check browser permissions.");
      }
    };

    loadData();
  }, []);

  // Safe-Save Logic: Only save if initial load is confirmed to prevent empty overwrites
  useEffect(() => {
    if (isInitialLoadDone.current) {
      try {
        localStorage.setItem('sganesh_bills', JSON.stringify(bills));
        localStorage.setItem('sganesh_services', JSON.stringify(services));
        localStorage.setItem('sganesh_expenses', JSON.stringify(expenses));
        localStorage.setItem('sganesh_personal', JSON.stringify(personalTransactions));
        localStorage.setItem('sganesh_subscription', JSON.stringify(subscription));
        setLastSync(new Date().toLocaleTimeString());
      } catch (e) {
        console.error("Critical Save Error (Quota likely exceeded):", e);
      }
    }
  }, [bills, services, expenses, personalTransactions, subscription]);

  // --- SUBSCRIPTION CALCULATION ---
  const PREMIUM_DURATION = 30; 
  const TRIAL_LIMIT_DAYS = 0; 
  const currentDate = new Date();

  let daysLeft = 0;
  let progressPercent = 0;

  if (subscription.isActivated && subscription.lastActivationDate) {
    const activationDate = new Date(subscription.lastActivationDate);
    const diffTime = Math.abs(currentDate.getTime() - activationDate.getTime());
    const daysPassed = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    daysLeft = Math.max(0, PREMIUM_DURATION - daysPassed);
    progressPercent = (daysLeft / PREMIUM_DURATION) * 100;
  } else {
    const installDate = new Date(subscription.installDate);
    const diffTime = Math.abs(currentDate.getTime() - installDate.getTime());
    const daysPassed = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    daysLeft = Math.max(0, TRIAL_LIMIT_DAYS - daysPassed);
    progressPercent = 0;
  }

  const isLocked = !subscription.isActivated && daysLeft <= 0;

  useEffect(() => {
    if (isLocked && !subscription.pendingKey) {
      const requestId = Math.random().toString(36).substring(2, 7).toUpperCase();
      setSubscription(prev => ({ ...prev, pendingKey: requestId }));
    }
  }, [isLocked, subscription.pendingKey]);

  useEffect(() => {
    if (subscription.isActivated && subscription.lastActivationDate) {
      const activationDate = new Date(subscription.lastActivationDate);
      const daysSince = Math.floor(Math.abs(new Date().getTime() - activationDate.getTime()) / (1000 * 60 * 60 * 24));
      if (daysSince >= PREMIUM_DURATION) {
         setSubscription(prev => ({ ...prev, isActivated: false, pendingKey: undefined }));
      }
    }
  }, [subscription.isActivated, subscription.lastActivationDate]);

  const handleActivate = (success: boolean) => {
    if (success) {
      setSubscription(prev => ({ 
        ...prev, 
        isActivated: true, 
        lastActivationDate: new Date().toISOString(),
        pendingKey: undefined
      }));
    }
  };

  const addBill = useCallback((newBill: Bill) => {
    setBills(prev => [newBill, ...prev]);
  }, []);

  const updateBillStatus = useCallback((id: string, status: 'Pending' | 'Paid') => {
    setBills(prev => prev.map(bill => bill.id === id ? { ...bill, status } : bill));
  }, []);

  const deleteBill = useCallback((id: string) => {
    if (window.confirm("Permanent Delete? This action cannot be undone.")) {
      setBills(prev => prev.filter(bill => bill.id !== id));
    }
  }, []);

  const exportToCSV = () => {
    if (bills.length === 0) return alert("No data to export");
    const headers = ["ID", "Customer", "Phone", "Date", "Time", "Total", "Status", "Items"];
    const rows = bills.map(b => [
      b.id, b.customerName, b.customerPhone, b.date, b.time, b.totalAmount, b.status,
      b.items.map(i => `${i.serviceName}(${i.quantity})`).join('; ')
    ]);
    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", `SG_Backup_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#F8FAFC] overflow-hidden relative pb-10">
      <style>{`
        @keyframes slide { from { transform: translateX(100%); } to { transform: translateX(-100%); } }
        .sliding-text { animation: slide 25s linear infinite; }
        .thin-scrollbar::-webkit-scrollbar { width: 4px; }
        .thin-scrollbar::-webkit-scrollbar-thumb { background: #CBD5E1; border-radius: 10px; }
      `}</style>

      {isLocked && (
        <LockOverlay 
          onActivate={handleActivate} 
          pendingKey={subscription.pendingKey || 'SG-AUTH'} 
        />
      )}

      {/* Professional Sidebar */}
      <nav className="w-full md:w-72 bg-[#0F172A] text-white flex-shrink-0 flex flex-col border-r border-slate-800 z-10">
        <div className="p-8 border-b border-slate-800 bg-slate-900/50">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-8 bg-orange-500 rounded-lg flex items-center justify-center">
              <i className="fas fa-print text-white text-xs"></i>
            </div>
            <h1 className="text-lg font-black text-white tracking-tight leading-none">
              SHREE GANESH
            </h1>
          </div>
          <p className="text-[9px] text-slate-500 uppercase tracking-[0.3em] font-black">Professional Flex ERP</p>
        </div>

        <div className="flex-1 py-6 space-y-1">
          {[
            { id: 'Billing', label: 'Create Invoice', icon: 'fa-plus-circle' },
            { id: 'History', label: 'Sales History', icon: 'fa-receipt' },
            { id: 'Analytics', label: 'Financial Profit', icon: 'fa-chart-line' },
            { id: 'Personal', label: 'Personal Vault', icon: 'fa-user-shield' }
          ].map((item) => (
            <button 
              key={item.id}
              onClick={() => setView(item.id as AppView)}
              className={`w-full text-left px-8 py-4 flex items-center space-x-4 transition-all relative ${view === item.id ? 'bg-orange-500 text-white' : 'hover:bg-slate-800/50 text-slate-400'}`}
            >
              {view === item.id && <div className="absolute left-0 top-0 bottom-0 w-1 bg-white"></div>}
              <i className={`fas ${item.icon} w-5 text-sm`}></i>
              <span className="font-bold text-sm tracking-wide">{item.label}</span>
            </button>
          ))}
        </div>

        {/* Persistence & License Monitor */}
        <div className="p-6 border-t border-slate-800 space-y-4 bg-slate-950/40">
          {/* Subscription Timeline */}
          <div className={`p-5 rounded-[24px] border transition-all duration-700 ${
            subscription.isActivated 
              ? 'bg-green-500/5 border-green-500/20 shadow-lg shadow-green-950/20' 
              : 'bg-orange-500/5 border-orange-500/20'
          }`}>
            <div className="flex justify-between items-start mb-3">
              <div>
                <p className={`text-[8px] font-black uppercase tracking-[0.2em] mb-1 ${
                  subscription.isActivated ? 'text-green-400' : 'text-orange-400'
                }`}>
                  {subscription.isActivated ? '• License Active' : '• System Trial'}
                </p>
                <p className="text-xl font-black text-white leading-none">
                  {daysLeft} <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest ml-1">Days Left</span>
                </p>
              </div>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center ${subscription.isActivated ? 'bg-green-500/20' : 'bg-orange-500/20'}`}>
                <i className={`fas ${subscription.isActivated ? 'fa-check-double text-green-400' : 'fa-hourglass-start text-orange-400'} text-[10px]`}></i>
              </div>
            </div>

            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden mb-3">
              <div 
                className={`h-full transition-all duration-1000 ease-in-out rounded-full ${
                  subscription.isActivated ? 'bg-green-500' : 'bg-orange-500'
                }`} 
                style={{ width: `${progressPercent}%` }}
              ></div>
            </div>
            <p className="text-[7px] text-slate-500 font-black uppercase tracking-widest text-center">
              Database Sync: {lastSync}
            </p>
          </div>

          <button 
            onClick={exportToCSV}
            className="w-full bg-slate-800 hover:bg-slate-700 text-white py-4 px-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center space-x-3 transition-all border border-slate-700 active:scale-95 group"
          >
            <i className="fas fa-cloud-download-alt text-slate-500 group-hover:text-white transition-colors"></i>
            <span>Export Master Backup</span>
          </button>

          <div className="flex items-center justify-center gap-2 py-2">
            <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
            <span className="text-[8px] text-slate-600 font-black uppercase tracking-[0.3em]">Database Secured</span>
          </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto thin-scrollbar">
        <div className="p-6 md:p-12 max-w-7xl mx-auto mb-16">
          {view === 'Billing' && (
            <BillingView 
              services={services} 
              onSave={addBill} 
              onAddService={(s) => setServices(prev => [...prev, s])}
              onDeleteService={(id) => setServices(prev => prev.filter(s => s.id !== id))}
            />
          )}
          {view === 'History' && (
            <HistoryView 
              bills={bills} 
              onUpdateStatus={updateBillStatus} 
              onDelete={deleteBill} 
            />
          )}
          {view === 'Analytics' && (
            <InsightsView 
              bills={bills} 
              expenses={expenses}
              onAddExpense={(e) => setExpenses(prev => [e, ...prev])}
              onDeleteExpense={(id) => setExpenses(prev => prev.filter(e => e.id !== id))}
            />
          )}
          {view === 'Personal' && (
            <PersonalView
              transactions={personalTransactions}
              onAdd={(t) => setPersonalTransactions(prev => [t, ...prev])}
              onDelete={(id) => setPersonalTransactions(prev => prev.filter(p => p.id !== id))}
            />
          )}
        </div>
      </main>

      {/* Security Credit Ticker */}
      <div className="fixed bottom-0 left-0 w-full bg-[#0F172A] border-t border-slate-800 h-10 flex items-center overflow-hidden z-20">
        <div className="sliding-text whitespace-nowrap text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
          Security: Active • Persistence: LocalStorage Verified • Developer: <span className="text-orange-500">Aniket Choudhari (+91 9960967852)</span> • All Billing Data is Encrypted & Saved Permanently • Do not clear browser cache to maintain records • Version 7.2 Release Stable • High Performance Mode Active
        </div>
      </div>
    </div>
  );
};

export default App;

