  const isLocked = !subscription.isActivated && daysLeft <= 0;

  useEffect(() => {
    if (isLocked && !subscription.pendingKey) {
      const requestId = Math.random().toString(36).substring(2, 7).toUpperCase();
      setSubscription(prev => ({ ...prev, pendingKey: requestId }));
    }
  }, [isLocked, subscription.pendingKey]);

  const handleActivate = (success: boolean) => {
    if (success) {
      setSubscription(prev => ({ 
        ...prev, 
        isActivated: true, 
        lastActivationDate: new Date().toISOString(),
        pendingKey: undefined
      }));
    }
  };

  const addBill = useCallback((newBill: Bill) => {
    setBills(prev => [newBill, ...prev]);
  }, []);

  const updateBillStatus = useCallback((id: string, status: 'Pending' | 'Paid') => {
