              className="w-full bg-slate-800 hover:bg-slate-700 text-white py-4 px-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center space-x-3 transition-all border border-slate-700 active:scale-95 group shadow-lg"
            >
              <i className="fas fa-file-csv text-orange-500 group-hover:text-white transition-colors"></i>
              <span>Download CSV Backup</span>
            </button>
            <div className="text-center">
               <p className="text-[7px] text-slate-500 font-bold uppercase tracking-widest">Last Backup: {lastBackupDate}</p>
            </div>
          </div>

          <div className="flex items-center justify-center gap-2 py-1">
            <div className="w-1.5 h-1.5 bg-green-500 rounded-full pulse-active"></div>
            <span className="text-[8px] text-slate-600 font-black uppercase tracking-[0.3em]">Permanent Persistence On</span>
          </div>
