          {view === 'Billing' && (
            <BillingView 
              services={services} 
              onSave={addBill} 
              onAddService={(s) => setServices(prev => [...prev, s])}
              onDeleteService={(id) => setServices(prev => prev.filter(s => s.id !== id))}
            />
          )}
          {view === 'History' && (
            <HistoryView 
              bills={bills} 
              onUpdateStatus={updateBillStatus} 
              onDelete={deleteBill} 
            />
