          {view === 'Personal' && (
            <PersonalView
              transactions={personalTransactions}
              onAdd={(t) => setPersonalTransactions(prev => [t, ...prev])}
              onDelete={(id) => setPersonalTransactions(prev => prev.filter(p => p.id !== id))}
            />
