          Persistence Layer: Verified • Database Sync: {lastSync} • Developer: <span className="text-orange-600">Aniket Choudhari (+91 9960967852)</span> • Note: Download CSV regularly for off-device security • High Availability Infrastructure • 100% Data Integrity Guaranteed • Local Engine Running
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Bill, Expense } from '../types';
import { 
  ComposedChart, 
  Bar, 
  Line, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer,
  Cell
} from 'recharts';

interface InsightsViewProps {
  bills: Bill[];
  expenses: Expense[];
  onAddExpense: (e: Expense) => void;
  onDeleteExpense: (id: string) => void;
}

const InsightsView: React.FC<InsightsViewProps> = ({ bills, expenses, onAddExpense, onDeleteExpense }) => {
  const [showAddExpense, setShowAddExpense] = useState(false);
  const [expAmount, setExpAmount] = useState<number>(0);
  const [expDesc, setExpDesc] = useState('');

  const handleAddExp = (e: React.FormEvent) => {
    e.preventDefault();
    if (!expAmount) return;
    onAddExpense({
      id: Math.random().toString(36).substr(2, 9),
      amount: expAmount,
      date: new Date().toLocaleDateString(),
      description: expDesc
    });
    setExpAmount(0);
    setDesc('');
    setShowAddExpense(false);
  };

  // Only calculate revenue from Paid bills
  const totalRevenue = bills
    .filter(b => b.status === 'Paid')
    .reduce((acc, bill) => acc + bill.totalAmount, 0);

  const totalExpenses = expenses.reduce((acc, exp) => acc + exp.amount, 0);

  const totalPending = bills
    .filter(b => b.status === 'Pending')
    .reduce((acc, bill) => acc + bill.totalAmount, 0);

  const netProfit = totalRevenue - totalExpenses;

  // Group by date for P&L chart (Last 7 Days)
  const last7Days = Array.from({ length: 7 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - i);
    return d.toLocaleDateString();
  }).reverse();

  const chartData = last7Days.map(date => {
    // Only count Paid bills for the daily revenue in chart
    const dailyRevenue = bills
      .filter(b => b.date === date && b.status === 'Paid')
      .reduce((sum, b) => sum + b.totalAmount, 0);

    const dailyExpenses = expenses
      .filter(e => e.date === date)
      .reduce((sum, e) => sum + e.amount, 0);

    return { 
      date, 
      Revenue: dailyRevenue, 
      Expenses: dailyExpenses,
      Profit: dailyRevenue - dailyExpenses
    };
  });

  const setDesc = (val: string) => setExpDesc(val);

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Header & Stats */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-2xl font-black text-gray-800 tracking-tight">Financial Overview</h2>
        <button 
          onClick={() => setShowAddExpense(!showAddExpense)}
          className="bg-red-500 hover:bg-red-600 text-white px-5 py-2.5 rounded-xl font-bold flex items-center shadow-lg shadow-red-100 transition-all"
        >
          <i className={`fas ${showAddExpense ? 'fa-times' : 'fa-minus-circle'} mr-2`}></i>
          {showAddExpense ? 'Cancel' : 'Record Expense'}
        </button>
      </div>

      {showAddExpense && (
        <form onSubmit={handleAddExp} className="bg-white p-6 rounded-2xl shadow-xl border border-red-100 flex flex-wrap gap-4 animate-slide-up">
          <div className="flex-1 min-w-[200px]">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Description</label>
            <input 
              type="text" 
              className="w-full bg-white border border-gray-200 rounded-lg p-2.5"
              placeholder="Rent, Raw material, etc."
              value={expDesc}
              onChange={e => setExpDesc(e.target.value)}
              required
            />
          </div>
          <div className="w-32">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Amount (₹)</label>
            <input 
              type="number" 
              className="w-full bg-white border border-gray-200 rounded-lg p-2.5 font-bold"
              value={expAmount}
              onChange={e => setExpAmount(parseFloat(e.target.value) || 0)}
              required
            />
          </div>
          <div className="flex items-end">
            <button type="submit" className="bg-slate-800 text-white px-6 py-2.5 rounded-lg font-bold">Save Expense</button>
          </div>
        </form>
      )}

      {/* Main KPI Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-green-50 text-green-600 rounded-2xl">
              <i className="fas fa-arrow-up text-xl"></i>
            </div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Total Paid (Revenue)</p>
              <h4 className="text-xl font-black text-gray-800">₹{totalRevenue.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-red-50 text-red-600 rounded-2xl">
              <i className="fas fa-arrow-down text-xl"></i>
            </div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Total Expenses</p>
              <h4 className="text-xl font-black text-gray-800">₹{totalExpenses.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-amber-50 text-amber-600 rounded-2xl">
              <i className="fas fa-clock text-xl"></i>
            </div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Total Pending</p>
              <h4 className="text-xl font-black text-amber-600">₹{totalPending.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>

        <div className={`p-6 rounded-3xl shadow-sm border ${netProfit >= 0 ? 'bg-orange-500 text-white border-orange-400' : 'bg-red-500 text-white border-red-400'}`}>
          <div className="flex items-center gap-4">
            <div className="p-3 bg-white/20 rounded-2xl">
              <i className="fas fa-wallet text-xl"></i>
            </div>
            <div>
              <p className="text-[10px] opacity-80 font-black uppercase tracking-widest">Real Profit</p>
              <h4 className="text-xl font-black">₹{netProfit.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
      </div>

      {/* Profit & Loss Chart */}
      <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
        <div className="flex justify-between items-center mb-10">
          <h3 className="text-xl font-black text-gray-800 flex items-center">
            <span className="w-2 h-8 bg-orange-500 rounded-full mr-3"></span>
            Daily Paid Revenue vs Expenses (7 Days)
          </h3>
          <div className="flex gap-4 text-xs font-bold text-gray-400">
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-green-400 rounded-sm"></span> Paid Revenue</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-red-400 rounded-sm"></span> Expenses</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-orange-500 rounded-full"></span> Net Profit</span>
          </div>
        </div>
        <div className="h-[450px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
              <XAxis dataKey="date" tick={{fontSize: 10, fill: '#94a3b8'}} axisLine={false} tickLine={false} dy={10} />
              <YAxis tick={{fontSize: 10, fill: '#94a3b8'}} axisLine={false} tickLine={false} dx={-10} />
              <Tooltip 
                cursor={{fill: '#f8fafc'}}
                contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.1)', padding: '12px'}}
              />
              <Legend verticalAlign="top" height={36}/>
              <Bar dataKey="Revenue" fill="#4ade80" radius={[6, 6, 0, 0]} barSize={40} />
              <Bar dataKey="Expenses" fill="#f87171" radius={[6, 6, 0, 0]} barSize={40} />
              <Area type="monotone" dataKey="Profit" fill="#fff7ed" stroke="none" />
              <Line type="monotone" dataKey="Profit" stroke="#f97316" strokeWidth={4} dot={{r: 6, fill: '#f97316', strokeWidth: 2, stroke: '#fff'}} />
            </ComposedChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Expense History List */}
      <div className="bg-white rounded-3xl border border-gray-100 overflow-hidden shadow-sm">
        <div className="px-8 py-6 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
          <h3 className="font-black text-gray-700 uppercase text-xs tracking-widest">Recent Expense Log</h3>
          <span className="text-[10px] bg-red-100 text-red-600 px-2 py-1 rounded font-bold">{expenses.length} Records</span>
        </div>
        <div className="max-h-96 overflow-y-auto thin-scrollbar">
          {expenses.length === 0 ? (
            <div className="p-20 text-center text-gray-300">
              <i className="fas fa-receipt text-3xl mb-3 opacity-20 block"></i>
              No expenses recorded yet.
            </div>
          ) : (
            <table className="w-full text-left">
              <tbody className="divide-y divide-gray-50">
                {expenses.map(exp => (
                  <tr key={exp.id} className="hover:bg-gray-50 group">
                    <td className="px-8 py-5">
                      <div className="text-sm font-bold text-gray-800">{exp.description}</div>
                      <div className="text-[10px] text-gray-400">{exp.date}</div>
                    </td>
                    <td className="px-8 py-5 text-right font-black text-red-500">
                      - ₹{exp.amount.toLocaleString('en-IN')}
                    </td>
                    <td className="px-8 py-5 text-right">
                      <button 
                        onClick={() => onDeleteExpense(exp.id)}
                        className="text-gray-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                      >
                        <i className="fas fa-trash"></i>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default InsightsView;

