        <div className="p-6 border-t border-slate-800 space-y-4 bg-slate-950/60">
          <div className="space-y-3">
             <div className="flex justify-between items-center px-1">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Safety Status</span>
                <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full ${isSyncing ? 'bg-orange-500/20 text-orange-400' : 'bg-green-500/20 text-green-400'}`}>
                  <div className={`w-1 h-1 rounded-full ${isSyncing ? 'bg-orange-400 animate-spin' : 'bg-green-400'}`}></div>
                  <span className="text-[8px] font-black uppercase">{isSyncing ? 'Saving' : 'Secured'}</span>
