import React, { useState } from 'react';
import { Bill } from '../types';
import { generateReminderMessage } from '../services/geminiService';

interface HistoryViewProps {
  bills: Bill[];
  onUpdateStatus: (id: string, status: 'Pending' | 'Paid') => void;
  onDelete: (id: string) => void;
}

const HistoryView: React.FC<HistoryViewProps> = ({ bills, onUpdateStatus, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sendingId, setSendingId] = useState<string | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const filteredBills = bills.filter(bill => 
    bill.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (bill.customerPhone && bill.customerPhone.includes(searchTerm)) ||
    bill.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleWhatsApp = async (bill: Bill) => {
    if (!bill.customerPhone) {
      alert("No phone number found for this customer.");
      return;
    }
    setSendingId(bill.id);
    const message = await generateReminderMessage(bill);
    setSendingId(null);
    const encodedMsg = encodeURIComponent(message);
    const phone = bill.customerPhone.replace(/\D/g, '');
    window.open(`https://wa.me/${phone.startsWith('91') ? phone : '91' + phone}?text=${encodedMsg}`, '_blank');
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-black text-gray-800 tracking-tight">Sales Records</h2>
        <div className="relative w-full md:w-96">
          <i className="fas fa-search absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
          <input
            type="text"
            placeholder="Search customer, bill ID..."
            className="w-full pl-12 pr-4 py-3 rounded-2xl border border-gray-200 focus:ring-2 focus:ring-orange-500 focus:outline-none bg-white font-medium"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left min-w-[800px]">
            <thead>
              <tr className="bg-gray-50/50 border-b border-gray-100">
                <th className="px-6 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">Client & Bill Info</th>
                <th className="px-6 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">Total Amount</th>
                <th className="px-6 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">Payment Status</th>
                <th className="px-6 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {filteredBills.map(bill => (
                <React.Fragment key={bill.id}>
                  <tr className="hover:bg-gray-50/30 transition-colors group">
                    <td className="px-6 py-5">
                      <div className="flex items-center gap-3">
                        <button 
                          onClick={() => setExpandedId(expandedId === bill.id ? null : bill.id)}
                          className="w-8 h-8 rounded-full bg-slate-100 text-slate-400 hover:text-orange-600 hover:bg-orange-50 transition-all flex items-center justify-center"
                        >
                          <i className={`fas ${expandedId === bill.id ? 'fa-chevron-up' : 'fa-chevron-down'} text-[10px]`}></i>
                        </button>
                        <div>
                          <div className="text-sm font-black text-gray-900">{bill.customerName}</div>
                          <div className="text-[10px] text-gray-400 font-bold uppercase tracking-widest flex items-center mt-0.5">
                            {bill.id} • {bill.date}
                            <span className="mx-2">|</span>
                            <i className="fab fa-whatsapp text-green-500 mr-1"></i> {bill.customerPhone || 'N/A'}
                          </div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <div className="text-lg font-black text-slate-800">₹{bill.totalAmount.toLocaleString('en-IN')}</div>
                      <div className="text-[10px] text-gray-400 font-bold uppercase">{bill.items.length} Job Items</div>
                    </td>
                    <td className="px-6 py-5 text-center">
                      <button 
                        onClick={() => onUpdateStatus(bill.id, bill.status === 'Paid' ? 'Pending' : 'Paid')}
                        className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${
                          bill.status === 'Paid' 
                            ? 'bg-green-50 text-green-700 border-green-200 hover:bg-green-100' 
                            : 'bg-orange-50 text-orange-700 border-orange-200 hover:bg-orange-100'
                        }`}
                      >
                        {bill.status}
                      </button>
                    </td>
                    <td className="px-6 py-5 text-right">
                      <div className="flex justify-end space-x-2">
                        {bill.status === 'Pending' && (
                          <button
                            onClick={() => handleWhatsApp(bill)}
                            disabled={sendingId === bill.id}
                            className="p-3 text-green-600 bg-green-50 hover:bg-green-100 rounded-xl transition-colors flex items-center gap-2 text-[10px] font-black uppercase tracking-widest disabled:opacity-50"
                          >
                            <i className={`fab fa-whatsapp ${sendingId === bill.id ? 'animate-spin' : ''}`}></i>
                            <span>Reminder</span>
                          </button>
                        )}
                        <button
                          onClick={() => onDelete(bill.id)}
                          className="p-3 text-red-600 bg-red-50 hover:bg-red-100 rounded-xl transition-colors"
                        >
                          <i className="fas fa-trash-alt"></i>
                        </button>
                      </div>
                    </td>
                  </tr>

                  {/* Expanded Item Details */}
                  {expandedId === bill.id && (
                    <tr className="bg-slate-50/50">
                      <td colSpan={4} className="px-10 py-6">
                        <div className="bg-white rounded-2xl border border-slate-100 shadow-inner overflow-hidden">
                          <table className="w-full text-left">
                            <thead>
                              <tr className="bg-slate-50 border-b border-slate-100">
                                <th className="px-4 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest">Job Service</th>
                                <th className="px-4 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Size (W x H)</th>
                                <th className="px-4 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Sqft / Unit</th>
                                <th className="px-4 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Rate</th>
                                <th className="px-4 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Qty</th>
                                <th className="px-4 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Amount</th>
                              </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                              {bill.items.map((item, idx) => (
                                <tr key={item.id + idx} className="text-xs">
                                  <td className="px-4 py-3 font-bold text-slate-700">{item.serviceName}</td>
                                  <td className="px-4 py-3 text-center text-slate-500 font-mono">
                                    {item.width > 0 ? `${item.width} x ${item.height}` : '-'}
                                  </td>
                                  <td className="px-4 py-3 text-center font-bold text-slate-500">
                                    {item.sqft > 0 ? `${item.sqft.toFixed(2)} ft²` : 'Fixed'}
                                  </td>
                                  <td className="px-4 py-3 text-center text-slate-500">₹{item.rate}</td>
                                  <td className="px-4 py-3 text-center font-bold text-slate-700">{item.quantity}</td>
                                  <td className="px-4 py-3 text-right font-black text-slate-900">₹{item.amount.toLocaleString('en-IN')}</td>
                                </tr>
                              ))}
                            </tbody>
                          </table>
                          {bill.notes && (
                            <div className="p-4 bg-orange-50/30 border-t border-slate-100">
                              <p className="text-[9px] font-black text-orange-600 uppercase tracking-widest mb-1">Office Notes</p>
                              <p className="text-xs text-slate-600 leading-relaxed italic">"{bill.notes}"</p>
                            </div>
                          )}
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              ))}
            </tbody>
          </table>
        </div>
        {filteredBills.length === 0 && (
          <div className="py-32 text-center">
            <i className="fas fa-folder-open text-gray-100 text-6xl mb-4"></i>
            <p className="text-gray-400 font-black uppercase tracking-widest text-sm">No sales data found matching your query</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryView;

import React, { useState } from 'react';
import { Bill, Expense } from '../types';
import { 
  ComposedChart, 
  Bar, 
  Line, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer
} from 'recharts';

interface InsightsViewProps {
  bills: Bill[];
  expenses: Expense[];
  onAddExpense: (e: Expense) => void;
  onDeleteExpense: (id: string) => void;
}

const InsightsView: React.FC<InsightsViewProps> = ({ bills, expenses, onAddExpense, onDeleteExpense }) => {
  const [showAddExpense, setShowAddExpense] = useState(false);
  const [expAmount, setExpAmount] = useState<number>(0);
  const [expDesc, setExpDesc] = useState('');

  const handleAddExp = (e: React.FormEvent) => {
    e.preventDefault();
    if (!expAmount) return;
    onAddExpense({
      id: Math.random().toString(36).substr(2, 9),
      amount: expAmount,
      date: new Date().toLocaleDateString(),
      description: expDesc
    });
    setExpAmount(0);
    setExpDesc('');
    setShowAddExpense(false);
  };

  const totalRevenue = bills
    .filter(b => b.status === 'Paid')
    .reduce((acc, bill) => acc + bill.totalAmount, 0);

  const totalExpenses = expenses.reduce((acc, exp) => acc + exp.amount, 0);

  const totalPending = bills
    .filter(b => b.status === 'Pending')
    .reduce((acc, bill) => acc + bill.totalAmount, 0);

  const netProfit = totalRevenue - totalExpenses;

  // Group by date for P&L chart (Last 30 Days)
  const last30Days = Array.from({ length: 30 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - i);
    return d.toLocaleDateString();
  }).reverse();

  const chartData = last30Days.map(date => {
    const dailyRevenue = bills
      .filter(b => b.date === date && b.status === 'Paid')
      .reduce((sum, b) => sum + b.totalAmount, 0);

    const dailyExpenses = expenses
      .filter(e => e.date === date)
      .reduce((sum, e) => sum + e.amount, 0);

    return { 
      date: date.split('/')[0] + '/' + date.split('/')[1], // Show only DD/MM on X-Axis
      Revenue: dailyRevenue, 
      Expenses: dailyExpenses,
      Profit: dailyRevenue - dailyExpenses
    };
  });

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-black text-gray-800 tracking-tight">Financial Intelligence</h2>
           <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">30-Day Monthly Performance Report</p>
        </div>
        <button 
          onClick={() => setShowAddExpense(!showAddExpense)}
          className="bg-red-500 hover:bg-red-600 text-white px-5 py-2.5 rounded-xl font-bold flex items-center shadow-lg shadow-red-100 transition-all"
        >
          <i className={`fas ${showAddExpense ? 'fa-times' : 'fa-minus-circle'} mr-2`}></i>
          {showAddExpense ? 'Cancel' : 'Record Expense'}
        </button>
      </div>

      {showAddExpense && (
        <form onSubmit={handleAddExp} className="bg-white p-6 rounded-2xl shadow-xl border border-red-100 flex flex-wrap gap-4 animate-slide-up">
          <div className="flex-1 min-w-[200px]">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Description</label>
            <input type="text" className="w-full bg-white border border-gray-200 rounded-lg p-2.5" placeholder="Rent, Raw material, etc." value={expDesc} onChange={e => setExpDesc(e.target.value)} required />
          </div>
          <div className="w-32">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Amount (₹)</label>
            <input type="number" className="w-full bg-white border border-gray-200 rounded-lg p-2.5 font-bold" value={expAmount} onChange={e => setExpAmount(parseFloat(e.target.value) || 0)} required />
          </div>
          <div className="flex items-end"><button type="submit" className="bg-slate-800 text-white px-6 py-2.5 rounded-lg font-bold">Save Expense</button></div>
        </form>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-green-50 text-green-600 rounded-2xl"><i className="fas fa-arrow-up text-xl"></i></div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Paid Revenue</p>
              <h4 className="text-xl font-black text-gray-800">₹{totalRevenue.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-red-50 text-red-600 rounded-2xl"><i className="fas fa-arrow-down text-xl"></i></div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Expenses</p>
              <h4 className="text-xl font-black text-gray-800">₹{totalExpenses.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-amber-50 text-amber-600 rounded-2xl"><i className="fas fa-clock text-xl"></i></div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Pending Dues</p>
              <h4 className="text-xl font-black text-amber-600">₹{totalPending.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
        <div className={`p-6 rounded-3xl shadow-sm border ${netProfit >= 0 ? 'bg-orange-500 text-white border-orange-400' : 'bg-red-500 text-white border-red-400'}`}>
          <div className="flex items-center gap-4">
            <div className="p-3 bg-white/20 rounded-2xl"><i className="fas fa-wallet text-xl"></i></div>
            <div>
              <p className="text-[10px] opacity-80 font-black uppercase tracking-widest">Real Profit</p>
              <h4 className="text-xl font-black">₹{netProfit.toLocaleString('en-IN')}</h4>
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-[40px] shadow-sm border border-gray-100">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
          <h3 className="text-xl font-black text-gray-800 flex items-center">
            <span className="w-2 h-8 bg-orange-500 rounded-full mr-3"></span>
            Monthly Revenue Flow (30 Days)
          </h3>
          <div className="flex flex-wrap gap-4 text-[9px] font-black uppercase tracking-widest text-gray-400">
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-green-400 rounded-sm"></span> Paid Revenue</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-red-400 rounded-sm"></span> Expenses</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-orange-500 rounded-full"></span> Net Profit</span>
          </div>
        </div>
        <div className="h-[500px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
              <XAxis dataKey="date" tick={{fontSize: 8, fill: '#94a3b8', fontWeight: 'bold'}} axisLine={false} tickLine={false} dy={10} interval={1} />
              <YAxis tick={{fontSize: 10, fill: '#94a3b8'}} axisLine={false} tickLine={false} dx={-10} />
              <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 10px 40px rgba(0,0,0,0.1)', padding: '16px'}} />
              <Legend verticalAlign="top" height={36}/>
              <Bar dataKey="Revenue" fill="#4ade80" radius={[4, 4, 0, 0]} barSize={12} />
              <Bar dataKey="Expenses" fill="#f87171" radius={[4, 4, 0, 0]} barSize={12} />
              <Area type="monotone" dataKey="Profit" fill="#fff7ed" stroke="none" />
              <Line type="monotone" dataKey="Profit" stroke="#f97316" strokeWidth={3} dot={{r: 3, fill: '#f97316', strokeWidth: 2, stroke: '#fff'}} />
            </ComposedChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-gray-100 overflow-hidden shadow-sm">
        <div className="px-8 py-6 bg-gray-50/50 border-b border-gray-100 flex justify-between items-center">
          <h3 className="font-black text-gray-700 uppercase text-xs tracking-widest">Recent Expense Log</h3>
          <span className="text-[10px] bg-red-100 text-red-600 px-2 py-1 rounded font-bold">{expenses.length} Records</span>
        </div>
        <div className="max-h-96 overflow-y-auto thin-scrollbar">
          {expenses.length === 0 ? (
            <div className="p-20 text-center text-gray-300"><i className="fas fa-receipt text-3xl mb-3 opacity-20 block"></i> No expenses recorded yet.</div>
          ) : (
            <table className="w-full text-left">
              <tbody className="divide-y divide-gray-50">
                {expenses.map(exp => (
                  <tr key={exp.id} className="hover:bg-gray-50 group">
                    <td className="px-8 py-5">
                      <div className="text-sm font-bold text-gray-800">{exp.description}</div>
                      <div className="text-[10px] text-gray-400 font-bold uppercase">{exp.date}</div>
                    </td>
                    <td className="px-8 py-5 text-right font-black text-red-500">- ₹{exp.amount.toLocaleString('en-IN')}</td>
                    <td className="px-8 py-5 text-right">
                      <button onClick={() => onDeleteExpense(exp.id)} className="text-gray-200 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><i className="fas fa-trash-alt"></i></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default InsightsView;

export interface Service {
  id: string;
  name: string;
  defaultRate: number; // rate per sqft or per unit
  category: 'sqft' | 'unit';
}

export interface BillItem {
  id: string;
  serviceId: string;
  serviceName: string;
  width: number;
  height: number;
  sqft: number;
  rate: number;
  quantity: number;
  amount: number;
  status: 'Pending' | 'Paid'; // Added individual status
}

export interface Bill {
  id: string;
  customerName: string;
  customerPhone: string;
  date: string;
  time: string;
  items: BillItem[];
  totalAmount: number;
  status: 'Pending' | 'Paid';
  notes: string;
}

export interface Expense {
  id: string;
  amount: number;
  date: string;
  description: string;
}

export interface PersonalTransaction {
  id: string;
  amount: number;
  date: string;
  description: string;
  category: string;
}

export type AppView = 'Billing' | 'History' | 'Analytics' | 'Personal';

export interface SubscriptionData {
  installDate: string;
  isActivated: boolean;
  lastActivationDate?: string;
  pendingKey?: string;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Bill, Service, AppView, Expense, PersonalTransaction, SubscriptionData } from './types';
import { DEFAULT_SERVICES, APP_TITLE } from './constants';
import BillingView from './components/BillingView';
import HistoryView from './components/HistoryView';
import InsightsView from './components/InsightsView';
import PersonalView from './components/PersonalView';
import LockOverlay from './components/LockOverlay';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('Billing');
  const [bills, setBills] = useState<Bill[]>([]);
  const [services, setServices] = useState<Service[]>(DEFAULT_SERVICES);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [personalTransactions, setPersonalTransactions] = useState<PersonalTransaction[]>([]);
  const [subscription, setSubscription] = useState<SubscriptionData>({
    installDate: new Date().toISOString(),
    isActivated: false
  });

  const [lastSync, setLastSync] = useState<string>(new Date().toLocaleTimeString());
  const [lastBackupDate, setLastBackupDate] = useState<string>(localStorage.getItem('sganesh_last_backup') || 'Never');
  const [isSyncing, setIsSyncing] = useState(false);
  const isInitialLoadDone = useRef(false);

  useEffect(() => {
    const loadData = () => {
      try {
        const savedBills = localStorage.getItem('sganesh_bills');
        const savedServices = localStorage.getItem('sganesh_services');
        const savedExpenses = localStorage.getItem('sganesh_expenses');
        const savedPersonal = localStorage.getItem('sganesh_personal');
        const savedSub = localStorage.getItem('sganesh_subscription');

        if (savedBills) setBills(JSON.parse(savedBills));
        if (savedServices) setServices(JSON.parse(savedServices));
        if (savedExpenses) setExpenses(JSON.parse(savedExpenses));
        if (savedPersonal) setPersonalTransactions(JSON.parse(savedPersonal));

        if (savedSub) {
          setSubscription(JSON.parse(savedSub));
        } else {
          const initialSub = { installDate: new Date().toISOString(), isActivated: false };
          setSubscription(initialSub);
          localStorage.setItem('sganesh_subscription', JSON.stringify(initialSub));
        }

        isInitialLoadDone.current = true;
      } catch (error) {
        console.error("Storage Restoration Error:", error);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (isInitialLoadDone.current) {
      setIsSyncing(true);
      try {
        localStorage.setItem('sganesh_bills', JSON.stringify(bills));
        localStorage.setItem('sganesh_services', JSON.stringify(services));
        localStorage.setItem('sganesh_expenses', JSON.stringify(expenses));
        localStorage.setItem('sganesh_personal', JSON.stringify(personalTransactions));
        localStorage.setItem('sganesh_subscription', JSON.stringify(subscription));
        setLastSync(new Date().toLocaleTimeString());
        setTimeout(() => setIsSyncing(false), 800);
      } catch (e) {
        setIsSyncing(false);
      }
    }
  }, [bills, services, expenses, personalTransactions, subscription]);

  const PREMIUM_DURATION = 30; 
  const TRIAL_LIMIT_DAYS = 0; 
  const currentDate = new Date();

  let daysLeft = 0;
  let progressPercent = 0;

  if (subscription.isActivated && subscription.lastActivationDate) {
    const activationDate = new Date(subscription.lastActivationDate);
    const diffTime = Math.abs(currentDate.getTime() - activationDate.getTime());
    const daysPassed = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    daysLeft = Math.max(0, PREMIUM_DURATION - daysPassed);
    progressPercent = (daysLeft / PREMIUM_DURATION) * 100;
  } else {
    const installDate = new Date(subscription.installDate);
    const diffTime = Math.abs(currentDate.getTime() - installDate.getTime());
    const daysPassed = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    daysLeft = Math.max(0, TRIAL_LIMIT_DAYS - daysPassed);
    progressPercent = 0;
  }

  const isLocked = !subscription.isActivated && daysLeft <= 0;

  useEffect(() => {
    if (isLocked && !subscription.pendingKey) {
      const requestId = Math.random().toString(36).substring(2, 7).toUpperCase();
      setSubscription(prev => ({ ...prev, pendingKey: requestId }));
    }
  }, [isLocked, subscription.pendingKey]);

  const handleActivate = (success: boolean) => {
    if (success) {
      setSubscription(prev => ({ 
        ...prev, 
        isActivated: true, 
        lastActivationDate: new Date().toISOString(),
        pendingKey: undefined
      }));
    }
  };

  const addBill = useCallback((newBill: Bill) => {
    setBills(prev => {
      const existingPendingIndex = prev.findIndex(b => 
        b.status === 'Pending' && 
        b.customerPhone === newBill.customerPhone &&
        b.customerPhone !== ''
      );

      if (existingPendingIndex !== -1) {
        const updatedBills = [...prev];
        const existingBill = updatedBills[existingPendingIndex];

        const mergedItems = [...existingBill.items, ...newBill.items];
        // Recalculate status: If all items (including new ones) are paid, set to Paid, else Pending
        const allPaid = mergedItems.every(item => item.status === 'Paid');

        updatedBills[existingPendingIndex] = {
          ...existingBill,
          items: mergedItems,
          totalAmount: existingBill.totalAmount + newBill.totalAmount,
          status: allPaid ? 'Paid' : 'Pending',
          notes: existingBill.notes + (newBill.notes ? ` | New Note: ${newBill.notes}` : ''),
          time: new Date().toLocaleTimeString()
        };
        alert(`Added items to ${newBill.customerName}'s account.`);
        return updatedBills;
      }
      return [newBill, ...prev];
    });
  }, []);

  const updateItemStatus = useCallback((billId: string, itemId: string, newStatus: 'Pending' | 'Paid') => {
    setBills(prev => prev.map(bill => {
      if (bill.id !== billId) return bill;

      const updatedItems = bill.items.map(item => 
        item.id === itemId ? { ...item, status: newStatus } : item
      );

      const allPaid = updatedItems.every(i => i.status === 'Paid');

      return {
        ...bill,
        items: updatedItems,
        status: allPaid ? 'Paid' : 'Pending'
      };
    }));
  }, []);

  const deleteBill = useCallback((id: string) => {
    if (window.confirm("PERMANENT DELETE? This entry will be erased from browser memory forever.")) {
      setBills(prev => prev.filter(bill => bill.id !== id));
    }
  }, []);

  const exportToCSV = () => {
    if (bills.length === 0) return alert("No data to export");
    const headers = ["ID", "Customer", "Phone", "Date", "Time", "Total", "Status", "Items"];
    const rows = bills.map(b => [
      b.id, b.customerName, b.customerPhone, b.date, b.time, b.totalAmount, b.status,
      b.items.map(i => `${i.serviceName}(${i.quantity})[${i.status}]`).join('; ')
    ]);
    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const timestamp = new Date().toISOString().split('T')[0];
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", `SG_Backup_${timestamp}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    const backupTime = new Date().toLocaleString();
    setLastBackupDate(backupTime);
    localStorage.setItem('sganesh_last_backup', backupTime);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#F8FAFC] overflow-hidden relative pb-10 font-sans">
      <style>{`
        @keyframes slide { from { transform: translateX(100%); } to { transform: translateX(-100%); } }
        .sliding-text { animation: slide 25s linear infinite; }
        .thin-scrollbar::-webkit-scrollbar { width: 4px; }
        .thin-scrollbar::-webkit-scrollbar-thumb { background: #CBD5E1; border-radius: 10px; }
        @keyframes pulse-green {
          0% { box-shadow: 0 0 0 0 rgba(34, 197, 94, 0.4); }
          70% { box-shadow: 0 0 0 10px rgba(34, 197, 94, 0); }
          100% { box-shadow: 0 0 0 0 rgba(34, 197, 94, 0); }
        }
        .pulse-active { animation: pulse-green 2s infinite; }
      `}</style>

      {isLocked && (
        <LockOverlay 
          onActivate={handleActivate} 
          pendingKey={subscription.pendingKey || 'SG-AUTH'} 
        />
      )}

      <nav className="w-full md:w-72 bg-[#0F172A] text-white flex-shrink-0 flex flex-col border-r border-slate-800 z-10 shadow-2xl">
        <div className="p-8 border-b border-slate-800 bg-slate-900/50">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-9 h-9 bg-orange-600 rounded-xl flex items-center justify-center shadow-lg shadow-orange-950/40">
              <i className="fas fa-print text-white text-sm"></i>
            </div>
            <h1 className="text-xl font-black text-white tracking-tighter leading-none">
              SHREE GANESH
            </h1>
          </div>
          <p className="text-[9px] text-slate-500 uppercase tracking-[0.4em] font-black">Professional ERP v7.5</p>
        </div>

        <div className="flex-1 py-6 space-y-1">
          {[
            { id: 'Billing', label: 'Create Invoice', icon: 'fa-plus-circle' },
            { id: 'History', label: 'Sales History', icon: 'fa-receipt' },
            { id: 'Analytics', label: 'Profit Analysis', icon: 'fa-chart-line' },
            { id: 'Personal', label: 'Private Vault', icon: 'fa-user-shield' }
          ].map((item) => (
            <button 
              key={item.id}
              onClick={() => setView(item.id as AppView)}
              className={`w-full text-left px-8 py-4 flex items-center space-x-4 transition-all relative group ${view === item.id ? 'bg-orange-600 text-white' : 'hover:bg-slate-800/40 text-slate-400 hover:text-slate-200'}`}
            >
              {view === item.id && <div className="absolute left-0 top-0 bottom-0 w-1.5 bg-white"></div>}
              <i className={`fas ${item.icon} w-5 text-sm transition-transform group-hover:scale-110`}></i>
              <span className="font-bold text-sm tracking-wide">{item.label}</span>
            </button>
          ))}
        </div>

        <div className="p-6 border-t border-slate-800 space-y-4 bg-slate-950/60">
          <div className="space-y-3">
             <div className="flex justify-between items-center px-1">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Safety Status</span>
                <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full ${isSyncing ? 'bg-orange-500/20 text-orange-400' : 'bg-green-500/20 text-green-400'}`}>
                  <div className={`w-1 h-1 rounded-full ${isSyncing ? 'bg-orange-400 animate-spin' : 'bg-green-400'}`}></div>
                  <span className="text-[8px] font-black uppercase">{isSyncing ? 'Saving' : 'Secured'}</span>
                </div>
             </div>
             <div className={`p-4 rounded-3xl border transition-all duration-700 ${subscription.isActivated ? 'bg-green-500/10 border-green-500/20' : 'bg-orange-500/10 border-orange-500/20'}`}>
               <div className="flex justify-between items-center mb-2">
                 <p className="text-[8px] font-black uppercase text-slate-400 tracking-widest">{subscription.isActivated ? 'Premium License' : 'System Trial'}</p>
                 <i className={`fas ${subscription.isActivated ? 'fa-crown text-yellow-500' : 'fa-clock text-orange-500'} text-[10px]`}></i>
               </div>
               <div className="text-xl font-black text-white leading-none mb-2">{daysLeft} <span className="text-[9px] text-slate-500 uppercase tracking-widest font-bold">Days Left</span></div>
               <div className="w-full bg-slate-800 h-1 rounded-full overflow-hidden">
                 <div className={`h-full transition-all duration-1000 ease-out rounded-full ${subscription.isActivated ? 'bg-green-500' : 'bg-orange-500'}`} style={{ width: `${progressPercent}%` }}></div>
               </div>
             </div>
          </div>
          <button onClick={exportToCSV} className="w-full bg-slate-800 hover:bg-slate-700 text-white py-4 px-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center space-x-3 transition-all border border-slate-700 shadow-lg">
            <i className="fas fa-file-csv text-orange-500"></i>
            <span>Download CSV Backup</span>
          </button>
          <div className="flex items-center justify-center gap-2 py-1">
            <div className="w-1.5 h-1.5 bg-green-500 rounded-full pulse-active"></div>
            <span className="text-[8px] text-slate-600 font-black uppercase tracking-[0.3em]">Permanent Persistence On</span>
          </div>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto thin-scrollbar">
        <div className="p-6 md:p-12 max-w-7xl mx-auto mb-20">
          {view === 'Billing' && <BillingView services={services} onSave={addBill} onAddService={(s) => setServices(prev => [...prev, s])} onDeleteService={(id) => setServices(prev => prev.filter(s => s.id !== id))} />}
          {view === 'History' && <HistoryView bills={bills} onUpdateItemStatus={updateItemStatus} onDelete={deleteBill} />}
          {view === 'Analytics' && <InsightsView bills={bills} expenses={expenses} onAddExpense={(e) => setExpenses(prev => [e, ...prev])} onDeleteExpense={(id) => setServices(prev => prev.filter(e => e.id !== id))} />}
          {view === 'Personal' && <PersonalView transactions={personalTransactions} onAdd={(t) => setPersonalTransactions(prev => [t, ...prev])} onDelete={(id) => setPersonalTransactions(prev => prev.filter(p => p.id !== id))} />}
        </div>
      </main>

      <div className="fixed bottom-0 left-0 w-full bg-[#0F172A] border-t border-slate-800 h-10 flex items-center overflow-hidden z-20">
        <div className="sliding-text whitespace-nowrap text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
          Persistence Layer: Verified • Database Sync: {lastSync} • Developer: <span className="text-orange-600">Aniket Choudhari (+91 9960967852)</span> • 30-Day Auto-History Tracking Enabled • 100% Data Integrity Guaranteed • Local Engine Running
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Bill, BillItem, Service } from '../types';

interface BillingViewProps {
  services: Service[];
  onSave: (bill: Bill) => void;
  onAddService: (service: Service) => void;
  onDeleteService: (id: string) => void;
}

const BillingView: React.FC<BillingViewProps> = ({ services, onSave, onAddService, onDeleteService }) => {
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [selectedItems, setSelectedItems] = useState<BillItem[]>([]);
  const [notes, setNotes] = useState('');

  const [showAddService, setShowAddService] = useState(false);
  const [newServiceName, setNewServiceName] = useState('');
  const [newServiceRate, setNewServiceRate] = useState<number>(0);
  const [newServiceCategory, setNewServiceCategory] = useState<'sqft' | 'unit'>('sqft');

  const handleAddService = () => {
    if (!newServiceName) return;
    onAddService({
      id: Math.random().toString(36).substr(2, 9),
      name: newServiceName,
      defaultRate: newServiceRate,
      category: newServiceCategory
    });
    setNewServiceName('');
    setNewServiceRate(0);
    setShowAddService(false);
  };

  const addServiceToBill = (service: Service) => {
    const newItem: BillItem = {
      id: Math.random().toString(36).substr(2, 9),
      serviceId: service.id,
      serviceName: service.name,
      width: service.category === 'sqft' ? 1 : 0,
      height: service.category === 'sqft' ? 1 : 0,
      sqft: service.category === 'sqft' ? 1 : 0,
      rate: service.defaultRate,
      quantity: 1,
      amount: service.defaultRate,
      status: 'Pending', // Default status
    };
    setSelectedItems(prev => [...prev, newItem]);
  };

  const updateItem = (id: string, updates: Partial<BillItem>) => {
    setSelectedItems(prev => prev.map(item => {
      if (item.id !== id) return item;
      const updated = { ...item, ...updates };
      if (updates.width !== undefined || updates.height !== undefined) {
        updated.sqft = updated.width * updated.height;
      }
      const service = services.find(s => s.id === updated.serviceId);
      if (service?.category === 'sqft') {
        updated.amount = updated.sqft * updated.rate * updated.quantity;
      } else {
        updated.amount = updated.rate * updated.quantity;
      }
      return updated;
    }));
  };

  const removeItem = (id: string) => {
    setSelectedItems(prev => prev.filter(i => i.id !== id));
  };

  const totalAmount = selectedItems.reduce((sum, item) => sum + item.amount, 0);

  const handleSave = () => {
    if (!customerName || selectedItems.length === 0) {
      alert("Please enter customer name and add at least one item.");
      return;
    }

    const newBill: Bill = {
      id: `INV-${Date.now()}`,
      customerName,
      customerPhone,
      date: new Date().toLocaleDateString(),
      time: new Date().toLocaleTimeString(),
      items: selectedItems,
      totalAmount,
      status: 'Pending',
      notes
    };

    onSave(newBill);
    setCustomerName('');
    setCustomerPhone('');
    setSelectedItems([]);
    setNotes('');
    alert("Bill generated and saved successfully.");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      <div className="lg:col-span-3 space-y-5">
        <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-black text-gray-800 text-sm uppercase tracking-wider flex items-center">
              <span className="w-1.5 h-4 bg-orange-500 rounded-full mr-2"></span>
              Service List
            </h3>
            <button 
              onClick={() => setShowAddService(!showAddService)}
              className="w-8 h-8 flex items-center justify-center bg-orange-500 text-white rounded-full hover:bg-orange-600 shadow-md shadow-orange-100"
            >
              <i className={`fas ${showAddService ? 'fa-times' : 'fa-plus'} text-xs`}></i>
            </button>
          </div>

          {showAddService && (
            <div className="mb-6 p-4 bg-orange-50 rounded-2xl border border-orange-100 space-y-3 animate-fade-in">
              <input 
                type="text" 
                placeholder="Job Name" 
                className="w-full p-2.5 text-sm border border-gray-200 rounded-xl bg-white focus:ring-2 focus:ring-orange-500 outline-none"
                value={newServiceName}
                onChange={e => setNewServiceName(e.target.value)}
              />
              <div className="flex gap-2">
                <input 
                  type="number" 
                  placeholder="Rate" 
                  className="w-1/2 p-2.5 text-sm border border-gray-200 rounded-xl bg-white focus:ring-2 focus:ring-orange-500 outline-none"
                  value={newServiceRate}
                  onChange={e => setNewServiceRate(parseFloat(e.target.value) || 0)}
                />
                <select 
                  className="w-1/2 p-2.5 text-sm border border-gray-200 rounded-xl bg-white outline-none"
                  value={newServiceCategory}
                  onChange={e => setNewServiceCategory(e.target.value as 'sqft' | 'unit')}
                >
                  <option value="sqft">Sqft</option>
                  <option value="unit">Unit</option>
                </select>
              </div>
              <button 
                onClick={handleAddService}
                className="w-full py-3 bg-slate-900 text-white text-xs font-black rounded-xl"
              >
                CREATE SERVICE
              </button>
            </div>
          )}

          <div className="grid grid-cols-1 gap-2.5 max-h-[60vh] overflow-y-auto pr-1 thin-scrollbar">
            {services.map(service => (
              <div key={service.id} className="flex group relative overflow-hidden rounded-2xl border border-gray-100 hover:border-orange-200 transition-all">
                <button
                  onClick={() => addServiceToBill(service)}
                  className="flex-1 text-left p-4 flex flex-col bg-white hover:bg-orange-50/50"
                >
                  <span className="text-sm font-bold text-gray-700 truncate mb-1">{service.name}</span>
                  <span className="text-[10px] font-black text-orange-600 bg-orange-100 w-fit px-2 py-0.5 rounded-full">₹{service.defaultRate} / {service.category}</span>
                </button>
                <button 
                  onClick={() => onDeleteService(service.id)}
                  className="px-3 text-gray-300 hover:text-red-500 hover:bg-red-50 transition-colors border-l border-gray-50"
                >
                  <i className="fas fa-trash-alt text-[10px]"></i>
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="lg:col-span-9 space-y-6">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-10 pb-6 border-b border-gray-50">
            <div className="flex-1 space-y-4">
              <h2 className="text-2xl font-black text-gray-800 tracking-tight">Invoice Generator</h2>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Customer Details</label>
                  <input
                    type="text"
                    placeholder="Enter Full Name"
                    className="w-full border-2 border-gray-100 rounded-2xl px-5 py-3.5 focus:border-orange-500 focus:ring-0 outline-none bg-white transition-all text-gray-800 font-bold"
                    value={customerName}
                    onChange={e => setCustomerName(e.target.value)}
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">WhatsApp / Contact</label>
                  <input
                    type="text"
                    placeholder="Mobile Number"
                    className="w-full border-2 border-gray-100 rounded-2xl px-5 py-3.5 focus:border-orange-500 focus:ring-0 outline-none bg-white transition-all text-gray-800 font-bold"
                    value={customerPhone}
                    onChange={e => setCustomerPhone(e.target.value)}
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[700px]">
              <thead>
                <tr className="text-[10px] font-black text-gray-400 uppercase tracking-widest border-b-2 border-gray-50">
                  <th className="py-4 px-2">Job Description</th>
                  <th className="py-4 px-2">Size (ft)</th>
                  <th className="py-4 px-2 text-center">Total Area</th>
                  <th className="py-4 px-2 text-center">Rate (₹)</th>
                  <th className="py-4 px-2 text-center">Qty</th>
                  <th className="py-4 px-2 text-right">Subtotal</th>
                  <th className="py-4 px-2"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50/50">
                {selectedItems.map(item => {
                  const s = services.find(sv => sv.id === item.serviceId);
                  const isSqft = s?.category === 'sqft';
                  return (
                    <tr key={item.id} className="hover:bg-gray-50/30 transition-colors animate-fade-in">
                      <td className="py-5 px-2">
                        <div className="font-black text-gray-800">{item.serviceName}</div>
                      </td>
                      <td className="py-5 px-2">
                        {isSqft && (
                          <div className="flex items-center gap-1.5">
                            <input 
                              type="number" 
                              className="w-16 border-2 border-gray-100 rounded-xl px-2 py-1.5 text-xs font-bold bg-white focus:border-orange-500 outline-none"
                              value={item.width}
                              onChange={e => updateItem(item.id, { width: parseFloat(e.target.value) || 0 })}
                            />
                            <span className="text-gray-300 font-black">×</span>
                            <input 
                              type="number" 
                              className="w-16 border-2 border-gray-100 rounded-xl px-2 py-1.5 text-xs font-bold bg-white focus:border-orange-500 outline-none"
                              value={item.height}
                              onChange={e => updateItem(item.id, { height: parseFloat(e.target.value) || 0 })}
                            />
                          </div>
                        )}
                      </td>
                      <td className="py-5 px-2 text-center">
                        <span className="text-xs font-black text-slate-500 bg-slate-100 px-2 py-1 rounded-lg">
                          {isSqft ? `${item.sqft.toFixed(2)} ft²` : 'Fixed'}
                        </span>
                      </td>
                      <td className="py-5 px-2 text-center">
                        <input 
                          type="number" 
                          className="w-24 border-2 border-orange-100 rounded-xl px-2 py-1.5 text-sm text-center font-black text-orange-600 bg-white focus:border-orange-500 outline-none"
                          value={item.rate}
                          onChange={e => updateItem(item.id, { rate: parseFloat(e.target.value) || 0 })}
                        />
                      </td>
                      <td className="py-5 px-2 text-center">
                        <input 
                          type="number" 
                          className="w-16 border-2 border-gray-100 rounded-xl px-2 py-1.5 text-sm text-center font-black bg-white focus:border-orange-500 outline-none"
                          value={item.quantity}
                          onChange={e => updateItem(item.id, { quantity: parseInt(e.target.value) || 1 })}
                        />
                      </td>
                      <td className="py-5 px-2 text-right font-black text-gray-900 text-lg">
                        ₹{item.amount.toLocaleString('en-IN')}
                      </td>
                      <td className="py-5 px-2 text-right">
                        <button 
                          onClick={() => removeItem(item.id)}
                          className="w-8 h-8 flex items-center justify-center text-red-200 hover:text-red-500 hover:bg-red-50 rounded-full transition-all"
                        >
                          <i className="fas fa-times"></i>
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          <div className="mt-12 pt-10 border-t-2 border-gray-50 grid grid-cols-1 md:grid-cols-2 gap-10">
            <div className="space-y-4">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Office Notes</label>
              <textarea
                className="w-full border-2 border-gray-100 rounded-3xl p-5 text-sm bg-white focus:border-orange-500 outline-none font-medium text-gray-600 min-h-[120px] transition-all"
                placeholder="Any special instructions..."
                value={notes}
                onChange={e => setNotes(e.target.value)}
              />
            </div>
            <div className="bg-slate-900 p-8 rounded-[40px] text-white flex flex-col justify-between shadow-2xl">
              <div className="flex justify-between items-center mb-8">
                <span className="text-xs font-black uppercase tracking-widest opacity-50">Grand Total</span>
                <span className="text-4xl font-black text-orange-400">₹{totalAmount.toLocaleString('en-IN')}</span>
              </div>
              <button 
                onClick={handleSave}
                disabled={selectedItems.length === 0}
                className="w-full py-5 rounded-2xl font-black text-sm uppercase tracking-widest bg-orange-500 hover:bg-orange-600 text-white disabled:opacity-50"
              >
                CONFIRM & SAVE BILL
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BillingView;

import React, { useState } from 'react';
import { Bill } from '../types';
import { generateReminderMessage } from '../services/geminiService';

interface HistoryViewProps {
  bills: Bill[];
  onUpdateItemStatus: (billId: string, itemId: string, status: 'Pending' | 'Paid') => void;
  onDelete: (id: string) => void;
}

const HistoryView: React.FC<HistoryViewProps> = ({ bills, onUpdateItemStatus, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sendingId, setSendingId] = useState<string | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const filteredBills = bills.filter(bill => 
    bill.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (bill.customerPhone && bill.customerPhone.includes(searchTerm)) ||
    bill.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleWhatsApp = async (bill: Bill) => {
    if (!bill.customerPhone) {
      alert("No phone number found for this customer.");
      return;
    }
    setSendingId(bill.id);
    const message = await generateReminderMessage(bill);
    setSendingId(null);
    const encodedMsg = encodeURIComponent(message);
    const phone = bill.customerPhone.replace(/\D/g, '');
    window.open(`https://wa.me/${phone.startsWith('91') ? phone : '91' + phone}?text=${encodedMsg}`, '_blank');
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-black text-gray-800 tracking-tight">Sales Records</h2>
        <div className="relative w-full md:w-96">
          <i className="fas fa-search absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
          <input
            type="text"
            placeholder="Search customer, phone, ID..."
            className="w-full pl-12 pr-4 py-3 rounded-2xl border border-gray-200 focus:ring-2 focus:ring-orange-500 outline-none bg-white"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left min-w-[800px]">
            <thead>
              <tr className="bg-gray-50/50 border-b border-gray-100">
                <th className="px-6 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">Client & Date</th>
                <th className="px-6 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">Billing Info</th>
                <th className="px-6 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">Payment Status</th>
                <th className="px-6 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {filteredBills.map(bill => (
                <React.Fragment key={bill.id}>
                  <tr className="hover:bg-gray-50/30 transition-colors group">
                    <td className="px-6 py-5">
                      <div className="flex items-center gap-3">
                        <button 
                          onClick={() => setExpandedId(expandedId === bill.id ? null : bill.id)}
                          className="w-8 h-8 rounded-full bg-slate-100 text-slate-400 hover:text-orange-600 hover:bg-orange-50 transition-all flex items-center justify-center"
                        >
                          <i className={`fas ${expandedId === bill.id ? 'fa-chevron-up' : 'fa-chevron-down'} text-[10px]`}></i>
                        </button>
                        <div>
                          <div className="text-sm font-black text-gray-900">{bill.customerName}</div>
                          <div className="text-[10px] text-gray-400 font-bold uppercase tracking-widest flex items-center mt-0.5">
                            {bill.date} • {bill.time}
                          </div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <div className="text-lg font-black text-slate-800">₹{bill.totalAmount.toLocaleString('en-IN')}</div>
                      <div className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
                         {bill.items.filter(i => i.status === 'Paid').length} / {bill.items.length} Jobs Paid
                      </div>
                    </td>
                    <td className="px-6 py-5 text-center">
                      <div className={`inline-flex px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${
                          bill.status === 'Paid' 
                            ? 'bg-green-50 text-green-700 border-green-200' 
                            : 'bg-orange-50 text-orange-700 border-orange-200'
                        }`}
                      >
                        {bill.status === 'Paid' ? 'Complete' : 'Pending Payment'}
                      </div>
                    </td>
                    <td className="px-6 py-5 text-right">
                      <div className="flex justify-end space-x-2">
                        {bill.status === 'Pending' && (
                          <button
                            onClick={() => handleWhatsApp(bill)}
                            disabled={sendingId === bill.id}
                            className="p-3 text-green-600 bg-green-50 hover:bg-green-100 rounded-xl disabled:opacity-50"
                          >
                            <i className={`fab fa-whatsapp ${sendingId === bill.id ? 'animate-spin' : ''}`}></i>
                          </button>
                        )}
                        <button
                          onClick={() => onDelete(bill.id)}
                          className="p-3 text-red-600 bg-red-50 hover:bg-red-100 rounded-xl"
                        >
                          <i className="fas fa-trash-alt"></i>
                        </button>
                      </div>
                    </td>
                  </tr>

                  {/* Expanded Item Details */}
                  {expandedId === bill.id && (
                    <tr className="bg-slate-50/50">
                      <td colSpan={4} className="px-10 py-6">
                        <div className="bg-white rounded-2xl border border-slate-100 shadow-inner overflow-hidden">
                          <table className="w-full text-left">
                            <thead>
                              <tr className="bg-slate-50 border-b border-slate-100">
                                <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">Job Service</th>
                                <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Specifications</th>
                                <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Amount</th>
                                <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Item Payment Status</th>
                              </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                              {bill.items.map((item, idx) => (
                                <tr key={item.id + idx} className="text-xs">
                                  <td className="px-4 py-4 font-bold text-slate-700">{item.serviceName}</td>
                                  <td className="px-4 py-4 text-center">
                                    <span className="text-[10px] text-slate-400 font-bold uppercase">
                                      {item.width > 0 ? `${item.width}x${item.height} (${item.sqft.toFixed(1)}ft²)` : 'Unit Based'}
                                      <span className="mx-2">•</span>
                                      Qty: {item.quantity}
                                    </span>
                                  </td>
                                  <td className="px-4 py-4 text-center font-black text-slate-900">₹{item.amount.toLocaleString('en-IN')}</td>
                                  <td className="px-4 py-4 text-right">
                                    <button 
                                      onClick={() => onUpdateItemStatus(bill.id, item.id, item.status === 'Paid' ? 'Pending' : 'Paid')}
                                      className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${
                                        item.status === 'Paid' 
                                          ? 'bg-green-500 text-white shadow-lg shadow-green-100' 
                                          : 'bg-slate-100 text-slate-400 hover:bg-orange-50 hover:text-orange-500'
                                      }`}
                                    >
                                      {item.status === 'Paid' ? <><i className="fas fa-check-circle mr-1"></i> Paid</> : 'Mark Paid'}
                                    </button>
                                  </td>
                                </tr>
                              ))}
                            </tbody>
                          </table>
                          {bill.notes && (
                            <div className="p-4 bg-orange-50/30 border-t border-slate-100">
                              <p className="text-[9px] font-black text-orange-600 uppercase tracking-widest mb-1">Office Remark</p>
                              <p className="text-xs text-slate-600 italic">"{bill.notes}"</p>
                            </div>
                          )}
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              ))}
            </tbody>
          </table>
        </div>
        {filteredBills.length === 0 && (
          <div className="py-32 text-center text-gray-300">
            <i className="fas fa-folder-open text-6xl mb-4 block opacity-10"></i>
            <span className="text-sm font-black uppercase tracking-widest">No matching records found</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryView;

import React, { useState } from 'react';
import { Bill, Expense } from '../types';
import { 
  ComposedChart, 
  Bar, 
  Line, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer
} from 'recharts';

interface InsightsViewProps {
  bills: Bill[];
  expenses: Expense[];
  onAddExpense: (e: Expense) => void;
  onDeleteExpense: (id: string) => void;
}

const InsightsView: React.FC<InsightsViewProps> = ({ bills, expenses, onAddExpense, onDeleteExpense }) => {
  const [showAddExpense, setShowAddExpense] = useState(false);
  const [expAmount, setExpAmount] = useState<number>(0);
  const [expDesc, setExpDesc] = useState('');

  const handleAddExp = (e: React.FormEvent) => {
    e.preventDefault();
    if (!expAmount) return;
    onAddExpense({
      id: Math.random().toString(36).substr(2, 9),
      amount: expAmount,
      date: new Date().toLocaleDateString(),
      description: expDesc
    });
    setExpAmount(0);
    setExpDesc('');
    setShowAddExpense(false);
  };

  // Calculate Revenue by summing all individual PAID items across all bills
  const totalRevenue = bills.reduce((acc, bill) => {
    const paidItemsTotal = bill.items
      .filter(item => item.status === 'Paid')
      .reduce((sum, item) => sum + item.amount, 0);
    return acc + paidItemsTotal;
  }, 0);

  const totalExpenses = expenses.reduce((acc, exp) => acc + exp.amount, 0);

  // Calculate Pending by summing all individual PENDING items across all bills
  const totalPending = bills.reduce((acc, bill) => {
    const pendingItemsTotal = bill.items
      .filter(item => item.status === 'Pending')
      .reduce((sum, item) => sum + item.amount, 0);
    return acc + pendingItemsTotal;
  }, 0);

  const netProfit = totalRevenue - totalExpenses;

  // Group by date for P&L chart (Last 30 Days)
  const last30Days = Array.from({ length: 30 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - i);
    return d.toLocaleDateString();
  }).reverse();

  const chartData = last30Days.map(date => {
    // Daily revenue comes from items marked as Paid that belong to bills from this date
    const dailyRevenue = bills
      .filter(b => b.date === date)
      .reduce((billSum, b) => {
        const paidItemsForDay = b.items
          .filter(item => item.status === 'Paid')
          .reduce((itemSum, item) => itemSum + item.amount, 0);
        return billSum + paidItemsForDay;
      }, 0);

    const dailyExpenses = expenses
      .filter(e => e.date === date)
      .reduce((sum, e) => sum + e.amount, 0);

    return { 
      date: date.split('/')[0] + '/' + date.split('/')[1], 
      Revenue: dailyRevenue, 
      Expenses: dailyExpenses,
      Profit: dailyRevenue - dailyExpenses
    };
  });

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-black text-gray-800 tracking-tight">Financial Intelligence</h2>
           <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Item-Level Revenue Analysis (30 Days)</p>
        </div>
        <button 
          onClick={() => setShowAddExpense(!showAddExpense)}
          className="bg-red-500 hover:bg-red-600 text-white px-5 py-2.5 rounded-xl font-bold flex items-center shadow-lg shadow-red-100 transition-all"
        >
          <i className={`fas ${showAddExpense ? 'fa-times' : 'fa-minus-circle'} mr-2`}></i>
          {showAddExpense ? 'Cancel' : 'Record Expense'}
        </button>
      </div>

      {showAddExpense && (
        <form onSubmit={handleAddExp} className="bg-white p-6 rounded-2xl shadow-xl border border-red-100 flex flex-wrap gap-4 animate-slide-up">
          <div className="flex-1 min-w-[200px]">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Description</label>
            <input type="text" className="w-full bg-white border border-gray-200 rounded-lg p-2.5 focus:ring-2 focus:ring-red-500 outline-none" placeholder="Rent, Raw material, etc." value={expDesc} onChange={e => setExpDesc(e.target.value)} required />
          </div>
          <div className="w-32">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Amount (₹)</label>
            <input type="number" className="w-full bg-white border border-gray-200 rounded-lg p-2.5 font-bold focus:ring-2 focus:ring-red-500 outline-none" value={expAmount} onChange={e => setExpAmount(parseFloat(e.target.value) || 0)} required />
          </div>
          <div className="flex items-end"><button type="submit" className="bg-slate-800 text-white px-6 py-2.5 rounded-lg font-bold">Save Expense</button></div>
        </form>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:border-green-200 transition-all">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-green-50 text-green-600 rounded-2xl"><i className="fas fa-wallet text-xl"></i></div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Paid Revenue</p>
              <h4 className="text-xl font-black text-gray-800">₹{totalRevenue.toLocaleString('en-IN')}</h4>
              <p className="text-[8px] text-green-500 font-bold uppercase tracking-tighter">Verified Items Only</p>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:border-red-200 transition-all">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-red-50 text-red-600 rounded-2xl"><i className="fas fa-arrow-down text-xl"></i></div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Expenses</p>
              <h4 className="text-xl font-black text-gray-800">₹{totalExpenses.toLocaleString('en-IN')}</h4>
              <p className="text-[8px] text-red-400 font-bold uppercase tracking-tighter">Operational Costs</p>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:border-amber-200 transition-all">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-amber-50 text-amber-600 rounded-2xl"><i className="fas fa-clock text-xl"></i></div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Pending Dues</p>
              <h4 className="text-xl font-black text-amber-600">₹{totalPending.toLocaleString('en-IN')}</h4>
              <p className="text-[8px] text-amber-500 font-bold uppercase tracking-tighter">Market Outstanding</p>
            </div>
          </div>
        </div>
        <div className={`p-6 rounded-3xl shadow-sm border transition-all ${netProfit >= 0 ? 'bg-orange-600 text-white border-orange-500' : 'bg-red-600 text-white border-red-500'}`}>
          <div className="flex items-center gap-4">
            <div className="p-3 bg-white/20 rounded-2xl"><i className="fas fa-chart-line text-xl"></i></div>
            <div>
              <p className="text-[10px] opacity-80 font-black uppercase tracking-widest">Net Realized Profit</p>
              <h4 className="text-xl font-black">₹{netProfit.toLocaleString('en-IN')}</h4>
              <p className="text-[8px] opacity-60 font-bold uppercase tracking-tighter">Revenue - Expenses</p>
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-[40px] shadow-sm border border-gray-100">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
          <h3 className="text-xl font-black text-gray-800 flex items-center">
            <span className="w-2 h-8 bg-orange-500 rounded-full mr-3"></span>
            Monthly Flow (Paid Items Only)
          </h3>
          <div className="flex flex-wrap gap-4 text-[9px] font-black uppercase tracking-widest text-gray-400">
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-green-400 rounded-sm"></span> Received</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-red-400 rounded-sm"></span> Spent</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 bg-orange-500 rounded-full"></span> Profit</span>
          </div>
        </div>
        <div className="h-[500px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
              <XAxis dataKey="date" tick={{fontSize: 8, fill: '#94a3b8', fontWeight: 'bold'}} axisLine={false} tickLine={false} dy={10} interval={1} />
              <YAxis tick={{fontSize: 10, fill: '#94a3b8'}} axisLine={false} tickLine={false} dx={-10} />
              <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 10px 40px rgba(0,0,0,0.1)', padding: '16px'}} />
              <Legend verticalAlign="top" height={36}/>
              <Bar dataKey="Revenue" fill="#4ade80" radius={[4, 4, 0, 0]} barSize={12} name="Realized Revenue" />
              <Bar dataKey="Expenses" fill="#f87171" radius={[4, 4, 0, 0]} barSize={12} name="Business Expenses" />
              <Area type="monotone" dataKey="Profit" fill="#fff7ed" stroke="none" />
              <Line type="monotone" dataKey="Profit" stroke="#f97316" strokeWidth={3} dot={{r: 3, fill: '#f97316', strokeWidth: 2, stroke: '#fff'}} name="Daily Profit" />
            </ComposedChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-gray-100 overflow-hidden shadow-sm">
        <div className="px-8 py-6 bg-gray-50/50 border-b border-gray-100 flex justify-between items-center">
          <h3 className="font-black text-gray-700 uppercase text-xs tracking-widest">Recent Expense Log</h3>
          <span className="text-[10px] bg-red-100 text-red-600 px-2 py-1 rounded font-bold">{expenses.length} Records</span>
        </div>
        <div className="max-h-96 overflow-y-auto thin-scrollbar">
          {expenses.length === 0 ? (
            <div className="p-20 text-center text-gray-300"><i className="fas fa-receipt text-3xl mb-3 opacity-20 block"></i> No expenses recorded yet.</div>
          ) : (
            <table className="w-full text-left">
              <tbody className="divide-y divide-gray-50">
                {expenses.map(exp => (
                  <tr key={exp.id} className="hover:bg-gray-50 group">
                    <td className="px-8 py-5">
                      <div className="text-sm font-bold text-gray-800">{exp.description}</div>
                      <div className="text-[10px] text-gray-400 font-bold uppercase">{exp.date}</div>
                    </td>
                    <td className="px-8 py-5 text-right font-black text-red-500">- ₹{exp.amount.toLocaleString('en-IN')}</td>
                    <td className="px-8 py-5 text-right">
                      <button onClick={() => onDeleteExpense(exp.id)} className="text-gray-200 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><i className="fas fa-trash-alt"></i></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default InsightsView;

