// Helper to safely initialize AI
const getAI = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey || apiKey === 'undefined') {
    console.warn("Gemini API Key is missing. Check your .env file or Vercel settings.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const generateReminderMessage = async (bill: Bill): Promise<string> => {
  const ai = getAI();
  if (!ai) {
    return `Hello ${bill.customerName}, this is a reminder regarding your pending payment of ₹${bill.totalAmount} at Shree Ganesh Flex. Please settle it at your earliest convenience. Thank you!`;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a polite and professional WhatsApp reminder message for a customer named ${bill.customerName} who has a pending bill of ₹${bill.totalAmount} at "Shree Ganesh Flex & Advertising". The bill date was ${bill.date}. Keep it concise and include a call to action to settle the payment.`,
    });
    return response.text || `Hello ${bill.customerName}, this is a reminder regarding your pending payment of ₹${bill.totalAmount} at Shree Ganesh Flex. Please settle it at your earliest convenience. Thank you!`;
  } catch (error) {
    console.error("Gemini Error:", error);
    return `Hello ${bill.customerName}, reminder for your pending bill of ₹${bill.totalAmount}. - Shree Ganesh Flex`;
  }
};

